{
  "name": "Prism: STEM Profile Reflection Tool",
  "description": "A vibrant, mobile-first profile-building tool designed specifically for Indian STEM students to reflect on their academic journey and prepare structured insights for personalized career guidance."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Section {
  BASIC = 'identity',
  ACADEMIC = 'academics',
  SKILLS = 'expertise',
  REFLECTIONS = 'reflections',
  REVIEW = 'review'
}

export interface Profile {
  fullName: string;
  email: string;
  location: string;
  degreeType: string;
  yearOfStudy: string;
  specialization: string;
  collegeName: string;
  cgpa: string;
  technicalSkills: string[];
  projects: string[];
  internships: string[];
  competitiveExams: string[];
  aspirations: {
    idealRole: string;
    industryInterest: string;
    higherStudies: boolean;
    researchInterest: boolean;
  };
  reflections: {
    toughestConcept: string;
    proudestAchievement: string;
    societalImpact: string;
    technicalObsession: string;
  };
}

export const INITIAL_PROFILE: Profile = {
  fullName: '',
  email: '',
  location: '',
  degreeType: '',
  yearOfStudy: '',
  specialization: '',
  collegeName: '',
  cgpa: '',
  technicalSkills: [],
  projects: [],
  internships: [],
  competitiveExams: [],
  aspirations: {
    idealRole: '',
    industryInterest: '',
    higherStudies: false,
    researchInterest: false
  },
  reflections: {
    toughestConcept: '',
    proudestAchievement: '',
    societalImpact: '',
    technicalObsession: ''
  }
};

import React, { useState, useEffect } from 'react';
import { Section, Profile, INITIAL_PROFILE } from './types';
import IdentityForm from './components/IdentityForm';
import AcademicForm from './components/AcademicForm';
import ExpertiseForm from './components/ExpertiseForm';
import ReflectionForm from './components/ReflectionForm';
import ReviewPage from './components/ReviewPage';
import Navigation from './components/Navigation';
import WelcomeHero from './components/WelcomeHero';

const App: React.FC = () => {
  const [currentSection, setCurrentSection] = useState<Section>(Section.BASIC);
  const [profile, setProfile] = useState<Profile>(() => {
    const saved = localStorage.getItem('prism_profile');
    return saved ? JSON.parse(saved) : INITIAL_PROFILE;
  });
  const [isStarted, setIsStarted] = useState(false);

  useEffect(() => {
    localStorage.setItem('prism_profile', JSON.stringify(profile));
  }, [profile]);

  const updateProfile = (updates: Partial<Profile>) => {
    setProfile(prev => ({ ...prev, ...updates }));
  };

  const next = () => {
    const sections = Object.values(Section);
    const currentIndex = sections.indexOf(currentSection);
    if (currentIndex < sections.length - 1) {
      setCurrentSection(sections[currentIndex + 1]);
      window.scrollTo(0, 0);
    }
  };

  const back = () => {
    const sections = Object.values(Section);
    const currentIndex = sections.indexOf(currentSection);
    if (currentIndex > 0) {
      setCurrentSection(sections[currentIndex - 1]);
      window.scrollTo(0, 0);
    }
  };

  if (!isStarted) {
    return <WelcomeHero onStart={() => setIsStarted(true)} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col pb-32">
      {/* Header */}
      <header className="sticky top-0 z-20 bg-white/80 backdrop-blur-md border-b border-slate-200 px-6 py-4 flex justify-between items-center">
        <h1 className="text-xl font-bold bg-gradient-to-r from-indigo-600 to-pink-600 bg-clip-text text-transparent">
          Prism
        </h1>
        <div className="flex items-center gap-2">
          <span className="text-xs font-medium text-slate-500 uppercase tracking-wider">
            {currentSection}
          </span>
          <div className="w-24 h-2 bg-slate-100 rounded-full overflow-hidden">
             <div 
               className="h-full bg-indigo-500 transition-all duration-500"
               style={{ width: `${(Object.values(Section).indexOf(currentSection) + 1) * 20}%` }}
             />
          </div>
        </div>
      </header>

      {/* Content */}
      <main className="flex-1 w-full max-w-2xl mx-auto px-6 pt-8">
        <div className="mb-8">
          <h2 className="text-2xl font-bold text-slate-900 mb-2">
            {currentSection === Section.BASIC && "Tell us who you are"}
            {currentSection === Section.ACADEMIC && "Academic Foundations"}
            {currentSection === Section.SKILLS && "Your Expertise Core"}
            {currentSection === Section.REFLECTIONS && "Deep Reflections"}
            {currentSection === Section.REVIEW && "Review Your Profile"}
          </h2>
          <p className="text-slate-500">
            {currentSection === Section.BASIC && "Basic details to anchor your identity in our career network."}
            {currentSection === Section.ACADEMIC && "Share your journey through Indian technical education."}
            {currentSection === Section.SKILLS && "Showcase what you've built and what you've learned."}
            {currentSection === Section.REFLECTIONS && "Answer these to help us understand how you think as an engineer/scientist."}
            {currentSection === Section.REVIEW && "Check your answers before finalizing your structured data."}
          </p>
        </div>

        {currentSection === Section.BASIC && (
          <IdentityForm profile={profile} updateProfile={updateProfile} />
        )}
        {currentSection === Section.ACADEMIC && (
          <AcademicForm profile={profile} updateProfile={updateProfile} />
        )}
        {currentSection === Section.SKILLS && (
          <ExpertiseForm profile={profile} updateProfile={updateProfile} />
        )}
        {currentSection === Section.REFLECTIONS && (
          <ReflectionForm profile={profile} updateProfile={updateProfile} />
        )}
        {currentSection === Section.REVIEW && (
          <ReviewPage profile={profile} setCurrentSection={setCurrentSection} />
        )}
      </main>

      {/* Footer Nav */}
      <Navigation 
        currentSection={currentSection} 
        onNext={next} 
        onBack={back} 
        isLast={currentSection === Section.REVIEW}
      />
    </div>
  );
};

export default App;

import React from 'react';

interface WelcomeHeroProps {
  onStart: () => void;
}

const WelcomeHero: React.FC<WelcomeHeroProps> = ({ onStart }) => {
  return (
    <div className="min-h-screen bg-slate-900 flex flex-col justify-center items-center px-8 relative overflow-hidden">
      {/* Decorative Blobs */}
      <div className="absolute top-[-10%] right-[-10%] w-96 h-96 bg-indigo-600/30 rounded-full blur-[100px]" />
      <div className="absolute bottom-[-10%] left-[-10%] w-96 h-96 bg-pink-600/30 rounded-full blur-[100px]" />

      <div className="relative z-10 text-center max-w-lg">
        <h1 className="text-5xl font-extrabold text-white mb-6 leading-tight">
          Reflect on your <span className="text-indigo-400">STEM</span> Journey.
        </h1>
        <p className="text-slate-300 text-lg mb-10 leading-relaxed">
          Building a personalized profile is the first step to meaningful career guidance. 
          Spend 10 minutes thinking about where you’ve been and where you’re going.
        </p>

        <div className="space-y-4">
          <button 
            onClick={onStart}
            className="w-full bg-indigo-500 hover:bg-indigo-600 text-white font-bold py-4 px-8 rounded-2xl transition-all shadow-xl shadow-indigo-500/20 text-lg"
          >
            Start Reflecting
          </button>
          <p className="text-slate-500 text-sm">
            For Indian Undergrads & Postgrads • Private & Voluntary
          </p>
        </div>
      </div>

      <div className="absolute bottom-10 left-0 right-0 text-center text-slate-500 text-xs px-12">
        <p>This tool helps you structure your thoughts for a personalized career chatbot experience.</p>
      </div>
    </div>
  );
};

export default WelcomeHero;

