export default AcademicForm;

import React, { useState } from 'react';
import { Profile } from '../types';
import { COMPETITIVE_EXAMS } from '../constants';

interface Props {
  profile: Profile;
  updateProfile: (updates: Partial<Profile>) => void;
}

const ExpertiseForm: React.FC<Props> = ({ profile, updateProfile }) => {
  const [skillInput, setSkillInput] = useState('');
  const [projectInput, setProjectInput] = useState('');

  const addSkill = () => {
    if (skillInput.trim() && !profile.technicalSkills.includes(skillInput.trim())) {
      updateProfile({ technicalSkills: [...profile.technicalSkills, skillInput.trim()] });
      setSkillInput('');
    }
  };

  const addProject = () => {
    if (projectInput.trim() && !profile.projects.includes(projectInput.trim())) {
      updateProfile({ projects: [...profile.projects, projectInput.trim()] });
      setProjectInput('');
    }
  };

  const toggleExam = (exam: string) => {
    const next = profile.competitiveExams.includes(exam)
      ? profile.competitiveExams.filter(e => e !== exam)
      : [...profile.competitiveExams, exam];
    updateProfile({ competitiveExams: next });
  };

  return (
    <div className="space-y-8 animate-in slide-in-from-right-4 duration-500">
      {/* Skills */}
      <div>
        <label className="block text-sm font-semibold text-slate-700 mb-2">Technical Skills</label>
        <div className="flex gap-2 mb-3">
          <input 
            type="text" 
            value={skillInput}
            onChange={(e) => setSkillInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && addSkill()}
            placeholder="e.g. Python, React, MATLAB, CAD"
            className="flex-1 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none"
          />
          <button 
            onClick={addSkill}
            className="px-4 py-2 bg-slate-900 text-white rounded-xl text-sm font-medium"
          >
            Add
          </button>
        </div>
        <div className="flex flex-wrap gap-2">
          {profile.technicalSkills.map(s => (
            <span key={s} className="px-3 py-1 bg-indigo-50 text-indigo-600 rounded-lg text-sm flex items-center gap-2 border border-indigo-100">
              {s}
              <button 
                onClick={() => updateProfile({ technicalSkills: profile.technicalSkills.filter(x => x !== s) })}
                className="hover:text-indigo-800"
              >
                &times;
              </button>
            </span>
          ))}
        </div>
      </div>

      {/* Projects */}
      <div>
        <label className="block text-sm font-semibold text-slate-700 mb-2">Key Projects</label>
        <div className="flex gap-2 mb-3">
          <input 
            type="text" 
            value={projectInput}
            onChange={(e) => setProjectInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && addProject()}
            placeholder="e.g. Smart Irrigation System"
            className="flex-1 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none"
          />
          <button 
            onClick={addProject}
            className="px-4 py-2 bg-slate-900 text-white rounded-xl text-sm font-medium"
          >
            Add
          </button>
        </div>
        <div className="flex flex-wrap gap-2">
          {profile.projects.map(p => (
            <span key={p} className="px-3 py-1 bg-emerald-50 text-emerald-600 rounded-lg text-sm border border-emerald-100 flex items-center gap-2">
              {p}
              <button 
                onClick={() => updateProfile({ projects: profile.projects.filter(x => x !== p) })}
                className="hover:text-emerald-800"
              >
                &times;
              </button>
            </span>
          ))}
        </div>
      </div>

      {/* Competitive Exams */}
      <div>
        <label className="block text-sm font-semibold text-slate-700 mb-2">Competitive Exams Preparing For</label>
        <div className="grid grid-cols-2 gap-2">
          {COMPETITIVE_EXAMS.map(exam => (
            <button
              key={exam}
              onClick={() => toggleExam(exam)}
              className={`text-left px-4 py-2 rounded-xl border transition-all text-xs sm:text-sm ${
                profile.competitiveExams.includes(exam) 
                ? 'bg-indigo-600 text-white border-indigo-600' 
                : 'bg-white text-slate-600 border-slate-200 hover:border-indigo-300'
              }`}
            >
              {exam}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
};

export default ExpertiseForm;

import React from 'react';
import { Profile } from '../types';
import { REFLECTION_PROMPTS } from '../constants';

interface Props {
  profile: Profile;
  updateProfile: (updates: Partial<Profile>) => void;
}

const ReflectionForm: React.FC<Props> = ({ profile, updateProfile }) => {
  return (
    <div className="space-y-10 animate-in slide-in-from-right-4 duration-500">
      {REFLECTION_PROMPTS.map((item) => (
        <div key={item.key} className="p-6 bg-white rounded-2xl border border-slate-100 shadow-sm">
          <div className="flex items-center gap-3 mb-4">
            <span className="flex items-center justify-center w-8 h-8 rounded-full bg-pink-100 text-pink-600 font-bold text-xs">
              ?
            </span>
            <h3 className="font-bold text-slate-800">{item.label}</h3>
          </div>
          <p className="text-slate-600 text-sm mb-4 leading-relaxed">
            {item.prompt}
          </p>
          <textarea 
            value={profile.reflections[item.key]}
            onChange={(e) => updateProfile({ 
              reflections: { ...profile.reflections, [item.key]: e.target.value } 
            })}
            placeholder="Type your reflection here..."
            className="w-full min-h-[120px] p-4 bg-slate-50 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm leading-relaxed"
          />
          <p className="mt-3 text-xs text-slate-400 italic">
            {item.example}
          </p>
        </div>
      ))}
    </div>
  );
};

export default ReflectionForm;

import React from 'react';
import { Profile, Section } from '../types';

interface Props {
  profile: Profile;
  setCurrentSection: (s: Section) => void;
}

const ReviewPage: React.FC<Props> = ({ profile, setCurrentSection }) => {
  const exportData = () => {
    const dataStr = JSON.stringify(profile, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `prism_profile_${profile.fullName.replace(/\s+/g, '_')}.json`;
    link.click();
  };

  const InfoBlock = ({ label, value, section }: { label: string, value: string | string[], section: Section }) => (
    <div className="mb-4 group">
      <div className="flex justify-between items-start mb-1">
        <span className="text-xs font-semibold text-slate-400 uppercase tracking-tighter">{label}</span>
        <button 
          onClick={() => setCurrentSection(section)}
          className="text-xs text-indigo-500 opacity-0 group-hover:opacity-100 transition-opacity"
        >
          Edit
        </button>
      </div>
      <p className="text-slate-800 text-sm font-medium break-words">
        {Array.isArray(value) ? value.join(', ') || 'Not specified' : value || 'Not specified'}
      </p>
    </div>
  );

  return (
    <div className="space-y-8 animate-in zoom-in-95 duration-500">
      <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-xl overflow-hidden relative">
        <div className="absolute top-0 right-0 p-8">
           <div className="w-12 h-12 bg-indigo-500 rounded-2xl transform rotate-12 flex items-center justify-center text-white font-bold text-2xl shadow-lg">
             {profile.fullName.charAt(0)}
           </div>
        </div>

        <section className="mb-8">
          <h3 className="text-sm font-bold text-indigo-600 mb-4 border-b pb-2">Identity & Academics</h3>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <InfoBlock label="Name" value={profile.fullName} section={Section.BASIC} />
            <InfoBlock label="Degree" value={`${profile.degreeType} - ${profile.specialization}`} section={Section.ACADEMIC} />
            <InfoBlock label="College" value={profile.collegeName} section={Section.ACADEMIC} />
            <InfoBlock label="Performance" value={profile.cgpa} section={Section.ACADEMIC} />
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-sm font-bold text-emerald-600 mb-4 border-b pb-2">Skills & Projects</h3>
          <InfoBlock label="Core Skills" value={profile.technicalSkills} section={Section.SKILLS} />
          <InfoBlock label="Key Projects" value={profile.projects} section={Section.SKILLS} />
          <InfoBlock label="Competitive Tracks" value={profile.competitiveExams} section={Section.SKILLS} />
        </section>

        <section className="mb-8">
          <h3 className="text-sm font-bold text-pink-600 mb-4 border-b pb-2">Reflections</h3>
          {Object.entries(profile.reflections).map(([key, val]) => (
            <InfoBlock key={key} label={key.replace(/([A-Z])/g, ' $1')} value={val} section={Section.REFLECTIONS} />
          ))}
        </section>

        <button 
          onClick={exportData}
          className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-3 hover:bg-black transition-all"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
          </svg>
          Export Profile JSON
        </button>
        <p className="text-center text-slate-400 text-[10px] mt-4 uppercase tracking-widest font-semibold">
          Ready to be shared with your career guide
        </p>
      </div>

      <div className="p-6 bg-indigo-50 border border-indigo-100 rounded-2xl">
         <h4 className="font-bold text-indigo-900 text-sm mb-2">Independent Thinking Only</h4>
         <p className="text-indigo-700 text-xs leading-relaxed">
           Prism does not provide AI coaching. The reflections above are your own thoughts, structured to help a future advisor understand your unique STEM journey in the Indian landscape.
         </p>
      </div>
    </div>
  );
};

export default ReviewPage;

import React from 'react';
import { Section } from '../types';

interface Props {
  currentSection: Section;
  onNext: () => void;
  onBack: () => void;
  isLast: boolean;
}

const Navigation: React.FC<Props> = ({ currentSection, onNext, onBack, isLast }) => {
  const sections = Object.values(Section);
  const isFirst = currentSection === sections[0];

  return (
    <div className="fixed bottom-0 left-0 right-0 p-6 bg-white/80 backdrop-blur-xl border-t border-slate-200 flex justify-center z-30">
      <div className="w-full max-w-2xl flex items-center gap-4">
        {!isFirst && (
          <button 
            onClick={onBack}
            className="flex-1 max-w-[100px] py-4 rounded-2xl border border-slate-200 text-slate-600 font-bold hover:bg-slate-50 transition-all text-sm"
          >
            Back
          </button>
        )}
        {!isLast && (
          <button 
            onClick={onNext}
            className="flex-1 py-4 rounded-2xl bg-indigo-600 text-white font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-all text-sm"
          >
            Continue to {sections[sections.indexOf(currentSection) + 1]}
          </button>
        )}
        {isLast && (
          <div className="flex-1 py-4 text-center text-emerald-600 font-bold bg-emerald-50 rounded-2xl text-sm border border-emerald-100">
            Profile Complete
          </div>
        )}
      </div>
    </div>
  );
};

