import React, { useState } from 'react';
import { Profile } from '../types';
import { COMPETITIVE_EXAMS, SOFT_SKILLS_SUGGESTIONS } from '../constants';

interface Props {
  profile: Profile;
  updateProfile: (updates: Partial<Profile>) => void;
}

const ExpertiseForm: React.FC<Props> = ({ profile, updateProfile }) => {
  const [skillInput, setSkillInput] = useState('');
  const [softSkillInput, setSoftSkillInput] = useState('');
  const [projectInput, setProjectInput] = useState('');

  const addSkill = () => {
    if (skillInput.trim() && !profile.technicalSkills.includes(skillInput.trim())) {
      updateProfile({ technicalSkills: [...profile.technicalSkills, skillInput.trim()] });
      setSkillInput('');
    }
  };

  const addSoftSkill = (skillName?: string) => {
    const val = (skillName || softSkillInput).trim();
    if (val && !profile.softSkills.includes(val)) {
      updateProfile({ softSkills: [...profile.softSkills, val] });
      setSoftSkillInput('');
    }
  };

  const addProject = () => {
    if (projectInput.trim() && !profile.projects.includes(projectInput.trim())) {
      updateProfile({ projects: [...profile.projects, projectInput.trim()] });
      setProjectInput('');
    }
  };

  const toggleExam = (exam: string) => {
    const next = profile.competitiveExams.includes(exam)
      ? profile.competitiveExams.filter(e => e !== exam)
      : [...profile.competitiveExams, exam];
    updateProfile({ competitiveExams: next });
  };

  return (
    <div className="space-y-10 animate-in slide-in-from-right-4 duration-500">
      {/* Hard Skills */}
      <div>
        <label className="block text-sm font-semibold text-slate-700 mb-2">Hard / Technical Skills</label>
        <p className="text-xs text-slate-500 mb-3">Languages, frameworks, tools, or laboratory techniques.</p>
        <div className="flex gap-2 mb-3">
          <input 
            type="text" 
            value={skillInput}
            onChange={(e) => setSkillInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && addSkill()}
            placeholder="e.g. Python, CRISPR, AutoCAD, Spectrophotometry"
            className="flex-1 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
          />
          <button 
            onClick={addSkill}
            className="px-6 bg-slate-900 text-white rounded-xl text-sm font-bold active:scale-95 transition-transform"
          >
            Add
          </button>
        </div>
        <div className="flex flex-wrap gap-2 min-h-[40px]">
          {profile.technicalSkills.map(s => (
            <span key={s} className="px-3 py-1 bg-indigo-50 text-indigo-700 rounded-lg text-sm flex items-center gap-2 border border-indigo-100 font-medium">
              {s}
              <button 
                onClick={() => updateProfile({ technicalSkills: profile.technicalSkills.filter(x => x !== s) })}
                className="hover:text-red-500 transition-colors"
              >
                &times;
              </button>
            </span>
          ))}
        </div>
      </div>

      {/* Soft Skills */}
      <div>
        <label className="block text-sm font-semibold text-slate-700 mb-2">Soft Skills / Professional Core</label>
        <p className="text-xs text-slate-500 mb-3">Essential for high-impact STEM careers.</p>
        <div className="flex gap-2 mb-4">
          <input 
            type="text" 
            value={softSkillInput}
            onChange={(e) => setSoftSkillInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && addSoftSkill()}
            placeholder="e.g. Technical Mentorship, Conflict Resolution"
            className="flex-1 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-pink-500 outline-none transition-all"
          />
          <button 
            onClick={() => addSoftSkill()}
            className="px-6 bg-pink-600 text-white rounded-xl text-sm font-bold active:scale-95 transition-transform"
          >
            Add
          </button>
        </div>

        <div className="mb-4">
          <p className="text-[10px] uppercase tracking-widest font-bold text-slate-400 mb-2">Suggestions</p>
          <div className="flex flex-wrap gap-2">
            {SOFT_SKILLS_SUGGESTIONS.filter(s => !profile.softSkills.includes(s)).slice(0, 6).map(suggestion => (
              <button
                key={suggestion}
                onClick={() => addSoftSkill(suggestion)}
                className="px-3 py-1 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-full text-xs transition-colors"
              >
                + {suggestion}
              </button>
            ))}
          </div>
        </div>

        <div className="flex flex-wrap gap-2 min-h-[40px]">
          {profile.softSkills.map(s => (
            <span key={s} className="px-3 py-1 bg-pink-50 text-pink-700 rounded-lg text-sm flex items-center gap-2 border border-pink-100 font-medium">
              {s}
              <button 
                onClick={() => updateProfile({ softSkills: profile.softSkills.filter(x => x !== s) })}
                className="hover:text-red-500 transition-colors"
              >
                &times;
              </button>
            </span>
          ))}
        </div>
      </div>

      {/* Projects */}
      <div>
        <label className="block text-sm font-semibold text-slate-700 mb-2">Key Projects & Research</label>
        <div className="flex gap-2 mb-3">
          <input 
            type="text" 
            value={projectInput}
            onChange={(e) => setProjectInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && addProject()}
            placeholder="e.g. Solar-powered Water Purifier"
            className="flex-1 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none"
          />
          <button 
            onClick={addProject}
            className="px-6 bg-slate-900 text-white rounded-xl text-sm font-bold active:scale-95 transition-transform"
          >
            Add
          </button>
        </div>
        <div className="flex flex-wrap gap-2">
          {profile.projects.map(p => (
            <span key={p} className="px-3 py-1 bg-emerald-50 text-emerald-700 rounded-lg text-sm border border-emerald-100 flex items-center gap-2 font-medium">
              {p}
              <button 
                onClick={() => updateProfile({ projects: profile.projects.filter(x => x !== p) })}
                className="hover:text-red-500 transition-colors"
              >
                &times;
              </button>
            </span>
          ))}
        </div>
      </div>

      {/* Competitive Exams */}
      <div>
        <label className="block text-sm font-semibold text-slate-700 mb-2">Competitive Exams & Certifications</label>
        <div className="grid grid-cols-2 gap-2">
          {COMPETITIVE_EXAMS.map(exam => (
            <button
              key={exam}
              onClick={() => toggleExam(exam)}
              className={`text-left px-4 py-2 rounded-xl border transition-all text-xs sm:text-sm font-medium ${
                profile.competitiveExams.includes(exam) 
                ? 'bg-indigo-600 text-white border-indigo-600 shadow-md scale-[0.98]' 
                : 'bg-white text-slate-600 border-slate-200 hover:border-indigo-300'
              }`}
            >
              {exam}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
};

export default ExpertiseForm;

