import React from 'react';
import { Profile } from '../types';
import { DEGREE_OPTIONS, STEM_HIERARCHY } from '../constants';

interface Props {
  profile: Profile;
  updateProfile: (updates: Partial<Profile>) => void;
}

const AcademicForm: React.FC<Props> = ({ profile, updateProfile }) => {
  const topLevels = Object.keys(STEM_HIERARCHY);
  const categories = profile.topLevelCategory ? Object.keys(STEM_HIERARCHY[profile.topLevelCategory]) : [];
  const subFields = (profile.topLevelCategory && profile.specializationCategory) 
    ? STEM_HIERARCHY[profile.topLevelCategory][profile.specializationCategory] 
    : [];

  return (
    <div className="space-y-6 animate-in slide-in-from-right-4 duration-500 pb-10">
      <div>
        <label className="block text-sm font-semibold text-slate-700 mb-2">College / University Name</label>
        <input 
          type="text" 
          value={profile.collegeName}
          onChange={(e) => updateProfile({ collegeName: e.target.value })}
          placeholder="e.g. IIT Madras, BITS Pilani, or local private/state colleges like VIT, SRM, or GEC Raipur"
          className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
        />
        <p className="text-[10px] text-slate-400 mt-2 italic font-medium">Include local, state, private, or premier institutions.</p>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-2">Degree Type</label>
          <select 
            value={profile.degreeType}
            onChange={(e) => updateProfile({ degreeType: e.target.value })}
            className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm"
          >
            <option value="">Select Degree</option>
            {DEGREE_OPTIONS.map(opt => <option key={opt} value={opt}>{opt}</option>)}
          </select>
        </div>
        <div>
          <label className="block text-sm font-semibold text-slate-700 mb-2">Year of Study</label>
          <select 
            value={profile.yearOfStudy}
            onChange={(e) => updateProfile({ yearOfStudy: e.target.value })}
            className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm"
          >
            <option value="">Select Year</option>
            {[1, 2, 3, 4, 5].map(y => (
              <option key={y} value={`${y}${y === 1 ? 'st' : y === 2 ? 'nd' : y === 3 ? 'rd' : 'th'} Year`}>
                {y}{y === 1 ? 'st' : y === 2 ? 'nd' : y === 3 ? 'rd' : 'th'} Year
              </option>
            ))}
            <option value="Alumnus">Alumni / Completed</option>
          </select>
        </div>
      </div>

      <div className="p-5 bg-slate-50 rounded-2xl border border-slate-100 space-y-5">
        <div>
          <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-3">Broad STEM Stream</label>
          <div className="flex gap-3">
            {topLevels.map(level => (
              <button
                key={level}
                onClick={() => updateProfile({ topLevelCategory: level, specializationCategory: '', specialization: '' })}
                className={`flex-1 py-3 rounded-xl border font-bold text-sm transition-all ${
                  profile.topLevelCategory === level 
                  ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' 
                  : 'bg-white border-slate-200 text-slate-600 hover:border-indigo-300'
                }`}
              >
                {level}
              </button>
            ))}
          </div>
        </div>

        {profile.topLevelCategory && (
          <div className="animate-in fade-in slide-in-from-top-2 duration-300">
            <label className="block text-sm font-semibold text-slate-700 mb-2">Subject Area</label>
            <select 
              value={profile.specializationCategory}
              onChange={(e) => updateProfile({ specializationCategory: e.target.value, specialization: '' })}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm"
            >
              <option value="">Select Subject Area</option>
              {categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
            </select>
          </div>
        )}

        {profile.specializationCategory && (
          <div className="animate-in fade-in slide-in-from-top-2 duration-300">
            <label className="block text-sm font-semibold text-slate-700 mb-2">Detailed Specialization</label>
            <select 
              value={profile.specialization}
              onChange={(e) => updateProfile({ specialization: e.target.value })}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm"
            >
              <option value="">Select Specialization</option>
              {subFields.map(sub => <option key={sub} value={sub}>{sub}</option>)}
            </select>
          </div>
        )}
      </div>

      <div>
        <label className="block text-sm font-semibold text-slate-700 mb-2">Current CGPA / Percentage</label>
        <input 
          type="text" 
          value={profile.cgpa}
          onChange={(e) => updateProfile({ cgpa: e.target.value })}
          placeholder="e.g. 8.5/10 or 75%"
          className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
        />
      </div>
    </div>
  );
};

export default AcademicForm;

import React from 'react';
import { Profile, Section } from '../types';

interface Props {
  profile: Profile;
  setCurrentSection: (s: Section) => void;
}

const ReviewPage: React.FC<Props> = ({ profile, setCurrentSection }) => {
  const exportData = () => {
    const dataStr = JSON.stringify(profile, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `prism_profile_${profile.fullName.replace(/\s+/g, '_') || 'unnamed'}.json`;
    link.click();
  };

  const InfoBlock = ({ label, value, section }: { label: string, value: string | string[], section: Section }) => (
    <div className="mb-4 group">
      <div className="flex justify-between items-start mb-1">
