          className="text-xs font-bold text-indigo-500 opacity-0 group-hover:opacity-100 transition-opacity"
        >
          Edit
        </button>
      </div>
      <p className="text-slate-800 text-sm font-medium break-words leading-relaxed">
        {Array.isArray(value) 
          ? (value.length > 0 ? value.join(', ') : <span className="text-slate-300 italic">Not specified</span>) 
          : (value || <span className="text-slate-300 italic">Not specified</span>)}
      </p>
    </div>
