        <section className="mb-10">
          <h3 className="text-xs font-black text-emerald-600 mb-6 border-b border-emerald-50 pb-2 uppercase tracking-widest">Core Competencies</h3>
          <div className="space-y-4">
            <InfoBlock label="Technical / Hard Skills" value={profile.technicalSkills} section={Section.SKILLS} />
