import React, { useState } from 'react';
import { Profile } from '../types';
import { COMPETITIVE_EXAMS, SOFT_SKILLS_SUGGESTIONS } from '../constants';

interface Props {
  profile: Profile;
  updateProfile: (updates: Partial<Profile>) => void;
}

const ExpertiseForm: React.FC<Props> = ({ profile, updateProfile }) => {
  const [skillInput, setSkillInput] = useState('');
  const [softSkillInput, setSoftSkillInput] = useState('');
  const [projectInput, setProjectInput] = useState('');
  const [internshipInput, setInternshipInput] = useState('');
  const [volunteeringInput, setVolunteeringInput] = useState('');
  const [interestInput, setInterestInput] = useState('');
  const [customExamInput, setCustomExamInput] = useState('');
  const [showCustomExam, setShowCustomExam] = useState(false);

  const addToList = (field: keyof Profile, value: string, setter: (v: string) => void) => {
    const trimmed = value.trim();
    const currentList = profile[field] as string[];
    if (trimmed && !currentList.includes(trimmed)) {
      updateProfile({ [field]: [...currentList, trimmed] });
      setter('');
    }
  };

  const removeFromList = (field: keyof Profile, value: string) => {
    const currentList = profile[field] as string[];
    updateProfile({ [field]: currentList.filter(x => x !== value) });
  };

  const toggleExam = (exam: string) => {
    const next = profile.competitiveExams.includes(exam)
      ? profile.competitiveExams.filter(e => e !== exam)
      : [...profile.competitiveExams, exam];
    updateProfile({ competitiveExams: next });
  };

  const SectionHeader = ({ title, subtitle }: { title: string, subtitle?: string }) => (
    <div className="mb-4">
      <label className="block text-sm font-bold text-slate-800 uppercase tracking-tight">{title}</label>
      {subtitle && <p className="text-xs text-slate-500">{subtitle}</p>}
    </div>
  );

  const InputRow = ({ value, onChange, onAdd, placeholder, colorClass = "indigo" }: any) => (
    <div className="flex gap-2 mb-3">
      <input 
        type="text" 
        value={value}
        onChange={(e) => onChange(e.target.value)}
        onKeyPress={(e) => e.key === 'Enter' && onAdd()}
        placeholder={placeholder}
        className="flex-1 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm"
      />
      <button 
        onClick={onAdd}
        className={`px-5 py-3 bg-slate-900 text-white rounded-xl text-xs font-black active:scale-95 transition-all uppercase tracking-widest`}
      >
        Add
      </button>
    </div>
  );

  const TagCloud = ({ items, field, color = "indigo" }: { items: string[], field: keyof Profile, color?: string }) => (
    <div className="flex flex-wrap gap-2 min-h-[32px]">
      {items.map(item => (
        <span key={item} className={`px-3 py-1.5 bg-${color}-50 text-${color}-700 rounded-lg text-xs flex items-center gap-2 border border-${color}-100 font-bold animate-in zoom-in-90`}>
          {item}
          <button onClick={() => removeFromList(field, item)} className="hover:text-red-500 text-lg leading-none">&times;</button>
        </span>
      ))}
    </div>
  );

  return (
    <div className="space-y-12 animate-in slide-in-from-right-4 duration-500 pb-20">

      {/* 1. Technical Skills */}
      <section>
        <SectionHeader title="Technical Core" subtitle="Software, Lab Techniques, or Scientific Methods" />
        <InputRow 
          value={skillInput} 
          onChange={setSkillInput} 
          onAdd={() => addToList('technicalSkills', skillInput, setSkillInput)} 
          placeholder="e.g. Python, SQL, Microscopy, PCB Design"
        />
        <TagCloud items={profile.technicalSkills} field="technicalSkills" />
      </section>

      {/* 2. Soft Skills */}
      <section>
        <SectionHeader title="Professional Strengths" subtitle="How you work and communicate" />
        <InputRow 
          value={softSkillInput} 
          onChange={setSoftSkillInput} 
          onAdd={() => addToList('softSkills', softSkillInput, setSoftSkillInput)} 
          placeholder="e.g. Mentorship, Data Storytelling"
        />
        <div className="flex flex-wrap gap-2 mb-3">
          {SOFT_SKILLS_SUGGESTIONS.filter(s => !profile.softSkills.includes(s)).slice(0, 5).map(s => (
            <button key={s} onClick={() => addToList('softSkills', s, () => {})} className="text-[10px] font-bold text-slate-400 border border-slate-100 px-2 py-1 rounded-md hover:bg-slate-50">+ {s}</button>
          ))}
        </div>
        <TagCloud items={profile.softSkills} field="softSkills" color="pink" />
      </section>

      {/* 3. Internships & Work */}
      <section>
        <SectionHeader title="Experiences" subtitle="Internships, Research Assistantships, or Work" />
        <InputRow 
          value={internshipInput} 
          onChange={setInternshipInput} 
          onAdd={() => addToList('internships', internshipInput, setInternshipInput)} 
          placeholder="e.g. Research Intern at ISRO, Junior Analyst at TechCorp"
        />
        <TagCloud items={profile.internships} field="internships" color="emerald" />
      </section>

      {/* 4. Projects & Volunteering */}
      <section className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div>
          <SectionHeader title="Key Projects" subtitle="Academic or Personal builds" />
          <InputRow 
            value={projectInput} 
            onChange={setProjectInput} 
            onAdd={() => addToList('projects', projectInput, setProjectInput)} 
            placeholder="e.g. AI Chatbot for Farmers"
          />
          <TagCloud items={profile.projects} field="projects" color="blue" />
        </div>
        <div>
          <SectionHeader title="Volunteering" subtitle="Giving back or community roles" />
          <InputRow 
            value={volunteeringInput} 
            onChange={setVolunteeringInput} 
            onAdd={() => addToList('volunteering', volunteeringInput, setVolunteeringInput)} 
            placeholder="e.g. Science Tutor for kids"
          />
          <TagCloud items={profile.volunteering} field="volunteering" color="violet" />
        </div>
      </section>

      {/* 5. Interests & Hobbies */}
      <section>
        <SectionHeader title="Interests & Hobbies" subtitle="What do you enjoy outside of study?" />
        <InputRow 
          value={interestInput} 
          onChange={setInterestInput} 
          onAdd={() => addToList('interests', interestInput, setInterestInput)} 
          placeholder="e.g. Astronomy, Photography, Cricket, Chess"
        />
        <TagCloud items={profile.interests} field="interests" color="amber" />
      </section>

      {/* 6. Exams & Certs */}
      <section>
        <SectionHeader title="Exams & Certifications" subtitle="Select all that apply" />
        <div className="grid grid-cols-2 gap-2 mb-4">
          {COMPETITIVE_EXAMS.map(exam => (
            <button
              key={exam}
              onClick={() => toggleExam(exam)}
              className={`text-left px-3 py-2 rounded-xl border transition-all text-[11px] font-bold ${
                profile.competitiveExams.includes(exam) 
                ? 'bg-indigo-600 text-white border-indigo-600 shadow-md' 
                : 'bg-white text-slate-500 border-slate-200 hover:border-indigo-200'
              }`}
            >
              {exam}
            </button>
          ))}
          <button
            onClick={() => setShowCustomExam(!showCustomExam)}
            className={`text-left px-3 py-2 rounded-xl border transition-all text-[11px] font-bold ${
              showCustomExam ? 'bg-slate-800 text-white' : 'bg-slate-50 text-slate-400 border-dashed border-slate-300'
            }`}
          >
            + Other (Specify)
          </button>
        </div>

        {showCustomExam && (
