import React, { useRef, useState, useEffect } from 'react';
import { Profile, INITIAL_PROFILE } from '../types';

interface WelcomeHeroProps {
  onStart: (importedProfile?: Profile) => void;
}

const WelcomeHero: React.FC<WelcomeHeroProps> = ({ onStart }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [hasDraft, setHasDraft] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem('prism_profile');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        // Basic check to see if it's more than just an empty initial profile
        if (parsed.fullName || parsed.collegeName || parsed.email) {
          setHasDraft(true);
        }
      } catch (e) {
        setHasDraft(false);
      }
    }
  }, []);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = JSON.parse(e.target?.result as string);
        // Simple validation: check for a key property
        if (json && typeof json === 'object' && 'fullName' in json) {
          onStart(json as Profile);
        } else {
          alert("Invalid profile file. Please upload a valid Prism JSON export.");
        }
      } catch (err) {
        alert("Error reading file. Please ensure it is a valid JSON.");
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="min-h-screen bg-slate-900 flex flex-col justify-center items-center px-8 relative overflow-hidden">
      {/* Decorative Blobs */}
