import React, { useState, useEffect } from 'react';
import { Section, Profile, INITIAL_PROFILE } from './types';
import IdentityForm from './components/IdentityForm';
import AcademicForm from './components/AcademicForm';
import ExpertiseForm from './components/ExpertiseForm';
import ReflectionForm from './components/ReflectionForm';
import ReviewPage from './components/ReviewPage';
import Navigation from './components/Navigation';
import WelcomeHero from './components/WelcomeHero';

const VIGYAN_SHAALA_LOGO = "https://vigyanshaala.com/wp-content/uploads/2021/01/VigyanShaala-Logo-Horizontal-1.png";
const STORAGE_KEY = 'vs_reflection_profile';

// Utility to ensure profile data is complete and backward compatible
const mergeProfileWithDefaults = (data: any): Profile => {
  if (!data) return INITIAL_PROFILE;
  return {
    ...INITIAL_PROFILE,
    ...data,
    aspirations: { 
      ...INITIAL_PROFILE.aspirations, 
      ...(data.aspirations || {}) 
    },
    reflections: { 
      ...INITIAL_PROFILE.reflections, 
      ...(data.reflections || {}) 
    },
    technicalSkills: Array.isArray(data.technicalSkills) ? data.technicalSkills : [],
    softSkills: Array.isArray(data.softSkills) ? data.softSkills : [],
    projects: Array.isArray(data.projects) ? data.projects : [],
    internships: Array.isArray(data.internships) ? data.internships : [],
    volunteering: Array.isArray(data.volunteering) ? data.volunteering : [],
    interests: Array.isArray(data.interests) ? data.interests : [],
    competitiveExams: Array.isArray(data.competitiveExams) ? data.competitiveExams : [],
  };
};

const App: React.FC = () => {
  const [currentSection, setCurrentSection] = useState<Section>(Section.BASIC);
  const [profile, setProfile] = useState<Profile>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        return mergeProfileWithDefaults(JSON.parse(saved));
      } catch (e) {
        return INITIAL_PROFILE;
      }
    }
    return INITIAL_PROFILE;
  });
  const [isStarted, setIsStarted] = useState(false);
  const [saveFeedback, setSaveFeedback] = useState(false);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(profile));
  }, [profile]);

  const updateProfile = (updates: Partial<Profile>) => {
    setProfile(prev => ({ ...prev, ...updates }));
  };

  const handleSaveDraft = () => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(profile));
    setSaveFeedback(true);
    setTimeout(() => setSaveFeedback(false), 2000);
  };

  const handleStart = (importedProfile?: Profile) => {
    if (importedProfile) {
      const merged = mergeProfileWithDefaults(importedProfile);
      setProfile(merged);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(merged));
    }
    setIsStarted(true);
  };

  const next = () => {
    const sections = Object.values(Section);
    const currentIndex = sections.indexOf(currentSection);
    if (currentIndex < sections.length - 1) {
      setCurrentSection(sections[currentIndex + 1]);
      window.scrollTo(0, 0);
    }
  };

  const back = () => {
    const sections = Object.values(Section);
    const currentIndex = sections.indexOf(currentSection);
    if (currentIndex > 0) {
      setCurrentSection(sections[currentIndex - 1]);
      window.scrollTo(0, 0);
    }
  };

  if (!isStarted) {
    return <WelcomeHero onStart={handleStart} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col pb-32">
      {/* Branded Etched Top Bar - Two Line Refined Layout */}
      <div className="bg-white/40 backdrop-blur-md py-2.5 text-center border-b border-slate-200/50 z-30 sticky top-0">
        <div className="flex flex-col items-center gap-1">
          <span className="text-[9px] font-black text-slate-500 uppercase tracking-[0.3em] leading-none">
            Quick Self-Reflection Tool
          </span>
          <span className="text-[8px] font-medium text-slate-400 uppercase tracking-[0.15em] leading-none">
            by VigyanShaala International
          </span>
        </div>
      </div>

      {/* Main Header - Adjusted top offset for the taller etched bar */}
      <header className="sticky top-[38px] z-20 bg-white/80 backdrop-blur-md border-b border-slate-200 px-6 py-4 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-3">
          <img 
            src={VIGYAN_SHAALA_LOGO} 
            alt="VigyanShaala Logo" 
            className="h-8 sm:h-10 object-contain"
          />
        </div>

        <div className="flex items-center gap-4">
          <button 
            onClick={handleSaveDraft}
            className={`flex items-center gap-2 px-3 py-1.5 rounded-lg border transition-all active:scale-95 text-[10px] font-black uppercase tracking-tighter sm:tracking-widest ${
              saveFeedback 
                ? 'bg-emerald-50 border-emerald-200 text-emerald-600' 
                : 'bg-white border-slate-200 text-slate-500 hover:bg-slate-50'
            }`}
          >
            {saveFeedback ? (
              <>
                <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" />
                </svg>
                <span>Draft Saved</span>
              </>
            ) : (
              <>
                <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 7H5a2 2 0 00-2 2v9a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-3m-1 4l-3 3m0 0l-3-3m3 3V4" />
                </svg>
                <span>Save Draft</span>
              </>
            )}
          </button>

          <div className="hidden sm:flex flex-col items-end">
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest leading-none mb-1">
              {currentSection}
            </span>
            <div className="w-24 h-1.5 bg-slate-100 rounded-full overflow-hidden">
               <div 
                 className="h-full bg-indigo-500 transition-all duration-500"
                 style={{ width: `${(Object.values(Section).indexOf(currentSection) + 1) * 20}%` }}
               />
            </div>
          </div>
        </div>
      </header>

      {/* Content */}
      <main className="flex-1 w-full max-w-2xl mx-auto px-6 pt-8">
        <div className="mb-8">
          <h2 className="text-2xl font-bold text-slate-900 mb-2">
            {currentSection === Section.BASIC && "Tell us who you are"}
            {currentSection === Section.ACADEMIC && "Academic Foundations"}
            {currentSection === Section.SKILLS && "Your Expertise Core"}
            {currentSection === Section.REFLECTIONS && "Deep Reflections"}
            {currentSection === Section.REVIEW && "Review Your Profile"}
          </h2>
          <p className="text-slate-500">
            {currentSection === Section.BASIC && "Basic details to anchor your identity in our career network."}
            {currentSection === Section.ACADEMIC && "Share your journey through Indian technical education."}
            {currentSection === Section.SKILLS && "Showcase what you've built and what you've learned."}
            {currentSection === Section.REFLECTIONS && "Answer these to help us understand how you think as an engineer/scientist."}
            {currentSection === Section.REVIEW && "Check your answers before finalizing your structured data."}
          </p>
        </div>

        {currentSection === Section.BASIC && (
          <IdentityForm profile={profile} updateProfile={updateProfile} />
        )}
        {currentSection === Section.ACADEMIC && (
          <AcademicForm profile={profile} updateProfile={updateProfile} />
        )}
        {currentSection === Section.SKILLS && (
          <ExpertiseForm profile={profile} updateProfile={updateProfile} />
        )}
        {currentSection === Section.REFLECTIONS && (
          <ReflectionForm profile={profile} updateProfile={updateProfile} />
        )}
        {currentSection === Section.REVIEW && (
          <ReviewPage profile={profile} setCurrentSection={setCurrentSection} />
        )}
      </main>

      {/* Footer Nav */}
      <Navigation 
        currentSection={currentSection} 
        onNext={next} 
        onBack={back} 
        isLast={currentSection === Section.REVIEW}
      />
    </div>
  );
};

