        >
          Edit
        </button>
      </div>
      <div className="text-slate-800 text-sm font-medium break-words leading-relaxed">
        {Array.isArray(value) 
          ? (value.length > 0 ? value.join(', ') : <span className="text-slate-300 italic">Not specified</span>) 
