import React, { useState } from 'react';
import { Profile, Section } from '../types';

interface Props {
  profile: Profile;
  setCurrentSection: (s: Section) => void;
}

const VIGYAN_SHAALA_LOGO = "https://vigyanshaala.com/wp-content/uploads/2021/01/VigyanShaala-Logo-Horizontal-1.png";
const STORAGE_KEY = 'vs_reflection_profile';

const ReviewPage: React.FC<Props> = ({ profile, setCurrentSection }) => {
  const [isSaved, setIsSaved] = useState(false);
  const [isUpdatingCurie, setIsUpdatingCurie] = useState(false);
  const [curieSuccess, setCurieSuccess] = useState(false);

  const saveLocally = () => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(profile));
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 3000);
  };

  const handleUpdateCurie = () => {
    // 1. Explicitly save locally first as requested
    localStorage.setItem(STORAGE_KEY, JSON.stringify(profile));

    setIsUpdatingCurie(true);
    // 2. Simulate syncing with the Curie career chatbot
    setTimeout(() => {
      setIsUpdatingCurie(false);
      setCurieSuccess(true);
      setTimeout(() => setCurieSuccess(false), 4000);
    }, 2000);
  };

  const exportData = () => {
    const dataStr = JSON.stringify(profile, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `vs_stem_profile_${profile.fullName.replace(/\s+/g, '_') || 'unnamed'}.json`;
    link.click();
  };

  const InfoBlock = ({ label, value, section }: { label: string, value: string | string[], section: Section }) => (
    <div className="mb-4 group">
      <div className="flex justify-between items-start mb-1">
        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{label}</span>
        <button 
          onClick={() => setCurrentSection(section)}
          className="text-[10px] font-black text-indigo-500 opacity-0 group-hover:opacity-100 transition-opacity uppercase"
        >
          Edit
        </button>
      </div>
      <div className="text-slate-800 text-sm font-medium break-words leading-relaxed">
        {Array.isArray(value) 
          ? (value.length > 0 ? value.join(', ') : <span className="text-slate-300 italic text-xs">Not specified</span>) 
          : (value || <span className="text-slate-300 italic text-xs">Not specified</span>)}
      </div>
    </div>
  );

  const displayCategory = profile.specializationCategory === 'Other' 
    ? profile.customCategory || 'Other' 
    : profile.specializationCategory;

  const displaySpecialization = profile.specialization === 'Other' 
    ? profile.customSpecialization || 'Other' 
    : profile.specialization;

  const specDisplay = [
    profile.topLevelCategory,
    displayCategory,
    displaySpecialization
  ].filter(Boolean).join(' / ');

  return (
    <div className="space-y-8 animate-in zoom-in-95 duration-500 pb-20">
      <div className="bg-white p-6 sm:p-10 rounded-3xl border border-slate-200 shadow-2xl overflow-hidden relative">
        <div className="absolute top-0 right-0 p-6 sm:p-10 flex flex-col items-end gap-3">
           <img 
            src={VIGYAN_SHAALA_LOGO} 
            alt="VigyanShaala" 
            className="h-10 object-contain opacity-80"
           />
           <div className="w-14 h-14 bg-gradient-to-br from-indigo-500 to-indigo-700 rounded-2xl transform rotate-12 flex items-center justify-center text-white font-black text-3xl shadow-xl">
             {profile.fullName ? profile.fullName.charAt(0).toUpperCase() : '?'}
           </div>
        </div>

        <div className="mb-10">
          <h2 className="text-2xl font-black text-slate-900 leading-tight">Structured Profile Data</h2>
          <p className="text-slate-500 text-xs mt-1 uppercase tracking-wider font-bold">Ready for Personalization</p>
        </div>

        <section className="mb-10">
          <h3 className="text-xs font-black text-indigo-600 mb-6 border-b border-indigo-50 pb-2 uppercase tracking-widest">Foundation</h3>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-8 gap-y-2">
            <InfoBlock label="Full Name" value={profile.fullName} section={Section.BASIC} />
            <InfoBlock label="Location" value={profile.location} section={Section.BASIC} />
            <InfoBlock label="Institution" value={profile.collegeName} section={Section.ACADEMIC} />
            <InfoBlock label="Degree Path" value={`${profile.degreeType} in ${specDisplay}`} section={Section.ACADEMIC} />
            <InfoBlock label="Performance" value={profile.cgpa} section={Section.ACADEMIC} />
            <InfoBlock label="Interests" value={profile.interests} section={Section.SKILLS} />
          </div>
        </section>

        <section className="mb-10">
          <h3 className="text-xs font-black text-emerald-600 mb-6 border-b border-emerald-50 pb-2 uppercase tracking-widest">Capabilities & Skills</h3>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-8">
            <InfoBlock label="Technical Skills" value={profile.technicalSkills} section={Section.SKILLS} />
            <InfoBlock label="Soft Skills" value={profile.softSkills} section={Section.SKILLS} />
