import React, { useState } from 'react';
import { Profile } from '../types';
import { COMPETITIVE_EXAMS, SOFT_SKILLS_SUGGESTIONS } from '../constants';

interface Props {
  profile: Profile;
  updateProfile: (updates: Partial<Profile>) => void;
}

const ExpertiseForm: React.FC<Props> = ({ profile, updateProfile }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [skillInput, setSkillInput] = useState('');
  const [softSkillInput, setSoftSkillInput] = useState('');
  const [projectInput, setProjectInput] = useState('');
  const [internshipInput, setInternshipInput] = useState('');
  const [volunteeringInput, setVolunteeringInput] = useState('');
  const [interestInput, setInterestInput] = useState('');
  const [customExamInput, setCustomExamInput] = useState('');
  const [showCustomExam, setShowCustomExam] = useState(false);

  const addToList = (field: keyof Profile, value: string, setter: (v: string) => void) => {
    if (!isEditing) return;
    const trimmed = value.trim();
    const currentList = (profile[field] as string[]) || [];
    if (trimmed && !currentList.includes(trimmed)) {
      updateProfile({ [field]: [...currentList, trimmed] });
      setter('');
    }
  };

  const removeFromList = (field: keyof Profile, value: string) => {
    if (!isEditing) return;
    const currentList = (profile[field] as string[]) || [];
    updateProfile({ [field]: currentList.filter(x => x !== value) });
  };

  const toggleExam = (exam: string) => {
    if (!isEditing) return;
    const currentExams = profile.competitiveExams || [];
    const next = currentExams.includes(exam)
      ? currentExams.filter(e => e !== exam)
      : [...currentExams, exam];
    updateProfile({ competitiveExams: next });
  };

  const SectionHeader = ({ title, subtitle }: { title: string, subtitle?: string }) => (
    <div className="mb-4">
      <label className="block text-sm font-bold text-slate-800 uppercase tracking-tight">{title}</label>
      {subtitle && <p className="text-xs text-slate-500">{subtitle}</p>}
    </div>
  );

  const InputRow = ({ value, onChange, onAdd, placeholder }: any) => (
    <div className={`flex gap-2 mb-3 ${!isEditing ? 'hidden' : ''}`}>
      <input 
        type="text" 
        value={value}
        onChange={(e) => onChange(e.target.value)}
        onKeyPress={(e) => e.key === 'Enter' && onAdd()}
        placeholder={placeholder}
        className="flex-1 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all text-sm"
      />
      <button 
        onClick={onAdd}
        className="px-5 py-3 bg-slate-900 text-white rounded-xl text-xs font-black active:scale-95 transition-all uppercase tracking-widest"
      >
        Add
      </button>
    </div>
  );

  const TagCloud = ({ items, field, color = "indigo" }: { items: string[], field: keyof Profile, color?: string }) => {
    const safeItems = items || [];
    return (
      <div className={`flex flex-wrap gap-2 min-h-[32px] ${!isEditing ? 'opacity-80' : ''}`}>
        {safeItems.length > 0 ? safeItems.map(item => (
          <span key={item} className={`px-3 py-1.5 bg-${color}-50 text-${color}-700 rounded-lg text-xs flex items-center gap-2 border border-${color}-100 font-bold`}>
            {item}
            {isEditing && (
              <button onClick={() => removeFromList(field, item)} className="hover:text-red-500 text-lg leading-none">&times;</button>
            )}
          </span>
        )) : <span className="text-xs text-slate-300 italic">No entries added</span>}
      </div>
    );
  };

  return (
    <div className="space-y-12 animate-in slide-in-from-right-4 duration-500 pb-20">
      <div className="flex justify-between items-center mb-2">
        <span className={`text-[10px] font-black uppercase tracking-widest px-2 py-1 rounded ${isEditing ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-100 text-slate-500'}`}>
          {isEditing ? 'Editing Mode' : 'Section Locked'}
        </span>
        <button 
          onClick={() => setIsEditing(!isEditing)}
          className={`flex items-center gap-2 px-4 py-1.5 rounded-lg text-xs font-bold transition-all border ${
            isEditing ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-indigo-600 border-indigo-200 hover:bg-indigo-50 shadow-sm'
          }`}
        >
          {isEditing ? (
            <><svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg> Lock & Save</>
          ) : (
            <><svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg> Edit Details</>
          )}
        </button>
      </div>

      <div className={`space-y-12 transition-all duration-300 ${!isEditing ? 'opacity-90' : 'opacity-100'}`}>
        <section>
          <SectionHeader title="Technical Core" />
          <InputRow value={skillInput} onChange={setSkillInput} onAdd={() => addToList('technicalSkills', skillInput, setSkillInput)} placeholder="e.g. Python, SQL..." />
          <TagCloud items={profile.technicalSkills} field="technicalSkills" />
        </section>

        <section>
          <SectionHeader title="Professional Strengths" />
          <InputRow value={softSkillInput} onChange={setSoftSkillInput} onAdd={() => addToList('softSkills', softSkillInput, setSoftSkillInput)} placeholder="e.g. Mentorship..." />
          <TagCloud items={profile.softSkills} field="softSkills" color="pink" />
        </section>

        <section>
          <SectionHeader title="Experiences" />
          <InputRow value={internshipInput} onChange={setInternshipInput} onAdd={() => addToList('internships', internshipInput, setInternshipInput)} placeholder="e.g. Research Intern..." />
          <TagCloud items={profile.internships} field="internships" color="emerald" />
        </section>

        <section className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div>
            <SectionHeader title="Key Projects" />
            <InputRow value={projectInput} onChange={setProjectInput} onAdd={() => addToList('projects', projectInput, setProjectInput)} placeholder="e.g. AI Chatbot..." />
            <TagCloud items={profile.projects} field="projects" color="blue" />
          </div>
          <div>
            <SectionHeader title="Volunteering" />
            <InputRow value={volunteeringInput} onChange={setVolunteeringInput} onAdd={() => addToList('volunteering', volunteeringInput, setVolunteeringInput)} placeholder="e.g. Science Tutor..." />
            <TagCloud items={profile.volunteering} field="volunteering" color="violet" />
          </div>
        </section>

        <section>
          <SectionHeader title="Exams & Certifications" />
          <div className="grid grid-cols-2 gap-2">
            {COMPETITIVE_EXAMS.map(exam => {
              const selected = (profile.competitiveExams || []).includes(exam);
              if (!isEditing && !selected) return null;
              return (
                <button
                  key={exam}
                  disabled={!isEditing}
                  onClick={() => toggleExam(exam)}
                  className={`text-left px-3 py-2 rounded-xl border transition-all text-[11px] font-bold ${
                    selected 
                    ? 'bg-indigo-600 text-white border-indigo-600 shadow-md' 
                    : 'bg-white text-slate-500 border-slate-200 hover:border-indigo-200'
                  }`}
                >
                  {exam}
                </button>
              );
            })}
          </div>
        </section>
      </div>

      {!isEditing && (
        <p className="text-[10px] text-slate-400 font-bold text-center italic">
          Click "Edit Details" above to add skills, projects, or certifications.
        </p>
      )}
    </div>
  );
};

export default ExpertiseForm;

