              {hasDraft && (
                <button onClick={handleFetchDraft} disabled={isFetching} className="w-full bg-slate-800 hover:bg-slate-700 text-slate-400 font-semibold py-3 px-8 rounded-2xl transition-all border border-white/5 text-xs active:scale-95 flex items-center justify-center gap-2">
                  {isFetching ? 'Loading draft...' : 'Resume Local Draft'}
                </button>
              )}
            </div>
          </div>
        </div>
        <FooterBranding />
      </div>
    );
  }

  // 2. WhatsApp Number Input Screen
  if (showWhatsAppInput && !showConfirmation) {
    return (
      <div className="min-h-screen bg-slate-900 flex flex-col items-center relative overflow-hidden">
        <div className="flex-1 flex flex-col justify-center items-center relative z-10 text-center max-w-2xl w-full px-6 py-12">
          <div className="animate-in slide-in-from-bottom-4 duration-500 w-full flex flex-col items-center">
            <button onClick={() => setShowWhatsAppInput(false)} className="mb-8 text-slate-500 hover:text-white flex items-center gap-2 text-sm font-bold uppercase tracking-widest transition-colors">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 19l-7-7 7-7" /></svg>
              Go Back
            </button>
            <h2 className="text-2xl sm:text-3xl font-black text-white mb-2 leading-tight">Sync your Curie Profile</h2>
            <p className="text-slate-400 text-sm mb-8">Enter your registered WhatsApp number to pre-fill your details.</p>
            <div className="w-full max-w-sm space-y-4">
              <div className="relative">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500 font-bold border-r border-slate-700 pr-3">+91</span>
                <input type="tel" value={whatsappNumber} onChange={(e) => setWhatsappNumber(e.target.value.replace(/\D/g, '').slice(0, 10))} placeholder="WhatsApp Number" className="w-full bg-slate-800/50 border border-slate-700 text-white pl-16 pr-4 py-5 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-lg tracking-widest" />
              </div>
              {error && <p className="text-pink-500 text-xs font-bold animate-pulse">{error}</p>}
              <button onClick={handleFetchByWhatsApp} disabled={isFetching || whatsappNumber.length < 10} className="w-full bg-indigo-500 hover:bg-indigo-600 disabled:bg-slate-700 disabled:opacity-50 text-white font-bold py-5 px-8 rounded-2xl transition-all shadow-xl shadow-indigo-500/20 text-lg active:scale-95 flex items-center justify-center gap-3">
                {isFetching ? (<><div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" /><span>Syncing...</span></>) : (<span>Retrieve Details</span>)}
              </button>
            </div>
          </div>
        </div>
        <FooterBranding />
      </div>
    );
  }

  // 3. Name Confirmation Screen
  if (showConfirmation && retrievedProfile) {
    return (
      <div className="min-h-screen bg-slate-900 flex flex-col items-center relative overflow-hidden">
        <div className="absolute top-[-10%] left-[-10%] w-96 h-96 bg-emerald-600/20 rounded-full blur-[100px]" />
        <div className="flex-1 flex flex-col justify-center items-center relative z-10 text-center max-w-2xl w-full px-6 py-12">
          <div className="animate-in zoom-in-95 duration-500 w-full flex flex-col items-center">
            <div className="w-24 h-24 bg-gradient-to-br from-indigo-500 to-pink-600 rounded-3xl flex items-center justify-center text-white text-4xl font-black mb-6 shadow-2xl border-4 border-white/10">
              {retrievedProfile.fullName.charAt(0)}
            </div>
            <h2 className="text-3xl sm:text-4xl font-black text-white mb-3 leading-tight">
              Is this you, <span className="text-indigo-400">{retrievedProfile.fullName.split(' ')[0]}</span>?
            </h2>
            <p className="text-slate-400 text-base mb-10 max-w-xs">
              We found your profile details linked to <span className="text-white font-mono">+91 {whatsappNumber}</span>.
            </p>

            <div className="flex flex-col gap-4 w-full max-w-xs">
              <button onClick={confirmAndStart} className="w-full bg-indigo-500 hover:bg-indigo-600 text-white font-bold py-5 rounded-2xl transition-all shadow-xl shadow-indigo-500/20 text-lg active:scale-95 flex items-center justify-center gap-2">
                Yes, that's me! 
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
              </button>
              <button onClick={resetFlow} className="w-full bg-white/5 hover:bg-white/10 text-slate-400 font-semibold py-4 rounded-2xl transition-all border border-white/10 text-sm active:scale-95">
                No, this isn't me
              </button>
            </div>
          </div>
        </div>
        <FooterBranding />
      </div>
    );
  }

  return null;
};

const FooterBranding = () => (
  <div className="relative z-10 w-full text-center px-6 mt-4 mb-8 leading-relaxed max-w-xl">
    <p className="text-slate-400 text-[10px] font-medium italic opacity-70 mb-2">
      Your data is shared only with Curie for personalized support.
    </p>
    <div className="flex flex-col items-center gap-0.5 opacity-30">
       <p className="text-[9px] font-black uppercase tracking-[0.2em]">Quick Self-Reflection Tool</p>
       <p className="text-[8px] font-bold uppercase tracking-[0.1em]">VigyanShaala International</p>
    </div>
  </div>
);

export default WelcomeHero;

