interface WelcomeHeroProps {
  onStart: (importedProfile?: Profile) => void;
}

const VIGYAN_SHAALA_LOGO = "https://vigyanshaala.com/wp-content/uploads/2021/01/VigyanShaala-Logo-Horizontal-1.png";
const STORAGE_KEY = 'vs_reflection_profile';

const WelcomeHero: React.FC<WelcomeHeroProps> = ({ onStart }) => {
  const [hasDraft, setHasDraft] = useState(false);
  const [isFetching, setIsFetching] = useState(false);
  const [showWhatsAppInput, setShowWhatsAppInput] = useState(false);
  const [showConfirmation, setShowConfirmation] = useState(false);
  const [retrievedProfile, setRetrievedProfile] = useState<Profile | null>(null);
  const [whatsappNumber, setWhatsappNumber] = useState('');
  const [error, setError] = useState('');

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.fullName || parsed.collegeName || parsed.email) {
          setHasDraft(true);
        }
      } catch (e) {
        setHasDraft(false);
      }
    }
  }, []);

  const handleFetchDraft = () => {
    setIsFetching(true);
    setTimeout(() => {
      onStart(); 
      setIsFetching(false);
    }, 800);
  };

  const handleFetchByWhatsApp = async () => {
    if (whatsappNumber.length < 10) {
      setError('Please enter a valid WhatsApp number');
      return;
    }
    setError('');
    setIsFetching(true);

    try {
      // Simulation of fetching user details from Curie's backend
      await new Promise(resolve => setTimeout(resolve, 1800));

      if (whatsappNumber.startsWith('9') || whatsappNumber.startsWith('8') || whatsappNumber === '1234567890') {
