import React, { useState } from 'react';
import { Profile } from '../types';
import { COMPETITIVE_EXAMS } from '../constants';

interface Props {
  profile: Profile;
  updateProfile: (updates: Partial<Profile>) => void;
}

const ExpertiseForm: React.FC<Props> = ({ profile, updateProfile }) => {
  const hasData = profile.technicalSkills.length > 0 || profile.softSkills.length > 0;
  const [isEditing, setIsEditing] = useState(!hasData);

  const [skillInput, setSkillInput] = useState('');
  const [softSkillInput, setSoftSkillInput] = useState('');
  const [projectInput, setProjectInput] = useState('');

  const addToList = (field: keyof Profile, value: string, setter: (v: string) => void) => {
    if (!isEditing) return;
    const trimmed = value.trim();
    const currentList = (profile[field] as string[]) || [];
    if (trimmed && !currentList.includes(trimmed)) {
      updateProfile({ [field]: [...currentList, trimmed] });
      setter('');
    }
  };

  const removeFromList = (field: keyof Profile, value: string) => {
    if (!isEditing) return;
    const currentList = (profile[field] as string[]) || [];
    updateProfile({ [field]: currentList.filter(x => x !== value) });
  };

  const toggleExam = (exam: string) => {
    if (!isEditing) return;
    const currentExams = profile.competitiveExams || [];
    const next = currentExams.includes(exam)
      ? currentExams.filter(e => e !== exam)
      : [...currentExams, exam];
    updateProfile({ competitiveExams: next });
  };

  const InputRow = ({ value, onChange, onAdd, placeholder }: any) => (
    <div className={`flex gap-2 mb-3 ${!isEditing ? 'hidden' : ''}`}>
      <input 
        type="text" 
        value={value}
        onChange={(e) => onChange(e.target.value)}
        onKeyPress={(e) => e.key === 'Enter' && onAdd()}
        placeholder={placeholder}
        className="flex-1 px-4 py-3 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-[#f58434] transition-all text-sm font-medium"
      />
      <button onClick={onAdd} className="px-5 py-3 bg-[#f58434] text-white rounded-xl text-xs font-black uppercase tracking-widest hover:bg-[#f58434]/90 transition-all shadow-md">Add</button>
    </div>
  );

  const TagCloud = ({ items, field, color = "vs-orange" }: { items: string[], field: keyof Profile, color?: string }) => {
    const safeItems = items || [];

    // Manual mapping for Tailwind classes based on brand colors
    const colorStyles: Record<string, string> = {
      'vs-orange': 'bg-[#f58434]/10 text-[#f58434] border-[#f58434]/20',
      'vs-yellow': 'bg-[#ffcd29]/10 text-[#b58e00] border-[#ffcd29]/20',
      'vs-blue': 'bg-[#2c4869]/10 text-[#2c4869] border-[#2c4869]/20'
    };

    return (
      <div className={`flex flex-wrap gap-2 min-h-[32px]`}>
        {safeItems.length > 0 ? safeItems.map(item => (
          <span key={item} className={`px-3 py-1.5 rounded-lg text-xs flex items-center gap-2 border font-black shadow-sm ${colorStyles[color] || colorStyles['vs-orange']}`}>
            {item}
            {isEditing && (
              <button onClick={() => removeFromList(field, item)} className="hover:text-red-500 text-lg leading-none">&times;</button>
            )}
          </span>
        )) : <span className="text-xs text-slate-300 italic font-medium">No entries yet</span>}
      </div>
    );
  };

  return (
    <div className="space-y-10 animate-in slide-in-from-right-4 duration-500 pb-20">
      <div className="flex justify-end items-center mb-2">
        <button 
          onClick={() => setIsEditing(!isEditing)}
          className={`flex items-center gap-2 px-4 py-1.5 rounded-lg text-xs font-black transition-all border ${
            isEditing ? 'bg-[#2c4869] text-white border-[#2c4869] shadow-lg' : 'bg-white text-[#f58434] border-[#f58434]/20 hover:bg-[#f58434]/5 shadow-sm'
          }`}
        >
          {isEditing ? (
            <><svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg> Save Core</>
          ) : (
            <><svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg> Edit Core</>
          )}
        </button>
      </div>

      <div className={`space-y-10 transition-all duration-300 ${!isEditing ? 'opacity-80' : 'opacity-100'}`}>
        <section>
          <label className="block text-xs font-black text-[#2c4869]/40 uppercase tracking-widest mb-3">Technical Stack</label>
          <InputRow value={skillInput} onChange={setSkillInput} onAdd={() => addToList('technicalSkills', skillInput, setSkillInput)} placeholder="e.g. Python, AWS..." />
          <TagCloud items={profile.technicalSkills} field="technicalSkills" color="vs-orange" />
        </section>

        <section>
          <label className="block text-xs font-black text-[#2c4869]/40 uppercase tracking-widest mb-3">Professional Skills</label>
          <InputRow value={softSkillInput} onChange={setSoftSkillInput} onAdd={() => addToList('softSkills', softSkillInput, setSoftSkillInput)} placeholder="e.g. Scientific Writing..." />
          <TagCloud items={profile.softSkills} field="softSkills" color="vs-yellow" />
        </section>

        <section>
          <label className="block text-xs font-black text-[#2c4869]/40 uppercase tracking-widest mb-3">Key Projects</label>
          <InputRow value={projectInput} onChange={setProjectInput} onAdd={() => addToList('projects', projectInput, setProjectInput)} placeholder="e.g. Solar Tracker..." />
          <TagCloud items={profile.projects} field="projects" color="vs-blue" />
        </section>

        <section>
          <label className="block text-xs font-black text-[#2c4869]/40 uppercase tracking-widest mb-3">Competitive Exams</label>
          <div className="grid grid-cols-2 gap-2">
            {COMPETITIVE_EXAMS.map(exam => {
              const selected = profile.competitiveExams.includes(exam);
              if (!isEditing && !selected) return null;
              return (
                <button
                  key={exam}
                  disabled={!isEditing}
                  onClick={() => toggleExam(exam)}
                  className={`text-left px-3 py-2 rounded-xl border transition-all text-[11px] font-black ${
                    selected 
                    ? 'bg-[#f58434] text-white border-[#f58434] shadow-sm' 
                    : 'bg-white text-[#2c4869]/60 border-slate-200 hover:border-[#ffcd29]'
                  }`}
                >
                  {exam}
                </button>
              );
            })}
          </div>
        </section>
      </div>
    </div>
  );
};

export default ExpertiseForm;

