import React from 'react';
import { Section } from '../types';

interface Props {
  currentSection: Section;
  onNext: () => void;
  onBack: () => void;
  isLast: boolean;
}

const Navigation: React.FC<Props> = ({ currentSection, onNext, onBack, isLast }) => {
  const sections = Object.values(Section);
  const isFirst = currentSection === sections[0];

  return (
    <div className="fixed bottom-0 left-0 right-0 p-6 bg-white/80 backdrop-blur-xl border-t border-slate-200 flex justify-center z-30">
      <div className="w-full max-w-2xl flex items-center gap-4">
        {!isFirst && (
          <button 
            onClick={onBack}
            className="flex-1 max-w-[100px] py-4 rounded-2xl border border-slate-200 text-[#2c4869] font-black hover:bg-slate-50 transition-all text-sm uppercase tracking-tight"
          >
            Back
          </button>
        )}
        {!isLast && (
          <button 
            onClick={onNext}
            className="flex-1 py-4 rounded-2xl bg-[#f58434] text-white font-black shadow-lg shadow-[#f58434]/20 hover:bg-[#f58434]/90 transition-all text-sm uppercase tracking-widest"
          >
            Continue to {sections[sections.indexOf(currentSection) + 1]}
          </button>
        )}
        {isLast && (
          <div className="flex-1 py-4 text-center text-emerald-600 font-black bg-emerald-50 rounded-2xl text-sm border border-emerald-100 uppercase tracking-widest">
            Profile Complete
          </div>
        )}
      </div>
    </div>
  );
};

