import React, { useState, useEffect } from 'react';
import { Profile } from '../types';

interface WelcomeHeroProps {
  onStart: (importedProfile?: Profile) => void;
}

const VIGYAN_SHAALA_LOGO = "https://vigyanshaala.com/wp-content/uploads/2021/01/VigyanShaala-Logo-Horizontal-1.png";
const STORAGE_KEY = 'vs_reflection_profile';

const WelcomeHero: React.FC<WelcomeHeroProps> = ({ onStart }) => {
  const [hasDraft, setHasDraft] = useState(false);
  const [isFetching, setIsFetching] = useState(false);
  const [showWhatsAppInput, setShowWhatsAppInput] = useState(false);
  const [showConfirmation, setShowConfirmation] = useState(false);
  const [retrievedProfile, setRetrievedProfile] = useState<Profile | null>(null);
  const [whatsappNumber, setWhatsappNumber] = useState('');
  const [error, setError] = useState('');

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.fullName || parsed.collegeName || parsed.email) {
          setHasDraft(true);
        }
      } catch (e) {
        setHasDraft(false);
      }
    }
  }, []);

  const handleFetchDraft = () => {
    setIsFetching(true);
    setTimeout(() => {
      onStart(); 
      setIsFetching(false);
    }, 800);
  };

  const handleFetchByWhatsApp = async () => {
    if (whatsappNumber.length < 10) {
      setError('Please enter a valid WhatsApp number');
      return;
    }
    setError('');
    setIsFetching(true);

    try {
      await new Promise(resolve => setTimeout(resolve, 1800));

      if (whatsappNumber.startsWith('9') || whatsappNumber.startsWith('8') || whatsappNumber === '1234567890') {
        const mockProfile: Partial<Profile> = {
          fullName: whatsappNumber.startsWith('9') ? "Ananya Iyer" : "Rahul Sharma",
          email: whatsappNumber.startsWith('9') ? "ananya.i@vigyanshaala.in" : "rahul.s@university.ac.in",
          location: whatsappNumber.startsWith('9') ? "Bengaluru, Karnataka" : "Pune, Maharashtra",
          collegeName: whatsappNumber.startsWith('9') ? "Vigyan Institute of Technology" : "Maharashtra Institute of Tech",
          degreeType: "B.Tech / B.E.",
          yearOfStudy: "3rd Year",
          topLevelCategory: "Engineering",
          specializationCategory: "Computer Science and Engineering (CSE)",
          specialization: "Cybersecurity",
          technicalSkills: ["Python", "C++", "Cyber Forensics", "SQL"],
          softSkills: ["Scientific Communication", "Leadership"],
          reflections: {
            strengths: "Logical analysis and deep focus on complex problem sets.",
            toughestConcept: "Abstract Algebra was hard, but I mastered it through group study.",
            technicalObsession: "The security implications of quantum computing.",
            proudestAchievement: "Presented a paper at a state-level STEM symposium.",
            societalImpact: "Optimizing rural energy grids using smart algorithms."
          }
        };
        setRetrievedProfile(mockProfile as Profile);
        setShowConfirmation(true);
      } else {
        setError("We couldn't find a Curie profile for this number.");
      }
    } catch (e) {
      setError("Unable to connect. Please try again.");
    } finally {
      setIsFetching(false);
    }
  };

  const confirmAndStart = () => {
    if (retrievedProfile) {
      onStart(retrievedProfile);
    }
  };

