        </div>
        <div className="flex-1 flex flex-col justify-center items-center relative z-10 text-center max-w-2xl w-full px-6 py-12">
          <div className="animate-in slide-in-from-bottom-4 duration-500 w-full flex flex-col items-center">
            <button onClick={() => setShowWhatsAppInput(false)} className="mb-8 text-white/60 hover:text-white flex items-center gap-2 text-sm font-black uppercase tracking-widest transition-colors">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 19l-7-7 7-7" /></svg>
