              {error && <p className="text-[#f58434] text-xs font-black animate-pulse uppercase">{error}</p>}
              <button onClick={handleFetchByWhatsApp} disabled={isFetching || whatsappNumber.length < 10} className="w-full bg-[#f58434] hover:bg-[#f58434]/90 disabled:bg-[#2c4869]/60 disabled:opacity-50 text-white font-black py-5 px-8 rounded-2xl transition-all shadow-xl shadow-[#f58434]/20 text-lg active:scale-95 flex items-center justify-center gap-3">
