              <button onClick={confirmAndStart} className="w-full bg-[#f58434] hover:bg-[#f58434]/90 text-white font-black py-5 rounded-2xl transition-all shadow-xl shadow-[#f58434]/20 text-lg active:scale-95 flex items-center justify-center gap-2">
                Yes, that's me! 
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
              </button>
              <button onClick={resetFlow} className="w-full bg-white/5 hover:bg-white/10 text-white/40 font-black py-4 rounded-2xl transition-all border border-white/10 text-sm active:scale-95 uppercase tracking-widest">
                No, this isn't me
              </button>
            </div>
          </div>
        </div>
        <FooterBranding />
      </div>
    );
  }

  return null;
};

