              disabled={!isEditing}
              value={profile.yearOfStudy}
              onChange={(e) => updateProfile({ yearOfStudy: e.target.value })}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 outline-none transition-all text-sm font-medium focus:ring-2 focus:ring-[#f58434]"
            >
              <option value="">Select Year</option>
              {[1, 2, 3, 4, 5].map(y => (
                <option key={y} value={`${y}${y === 1 ? 'st' : y === 2 ? 'nd' : y === 3 ? 'rd' : 'th'} Year`}>
                  {y}{y === 1 ? 'st' : y === 2 ? 'nd' : y === 3 ? 'rd' : 'th'} Year
