              <option value="Alumnus">Alumni</option>
            </select>
          </div>
        </div>

        <div className="p-5 bg-white rounded-2xl border border-slate-100 shadow-sm space-y-5">
          <div>
            <label className="block text-xs font-black text-[#2c4869]/40 uppercase tracking-widest mb-3">Broad STEM Stream</label>
