              {topLevels.map(level => (
                <button
                  key={level}
                  disabled={!isEditing}
                  onClick={() => updateProfile({ 
                    topLevelCategory: level, 
                    specializationCategory: '', 
                    specialization: ''
                  })}
                  className={`flex-1 py-3 rounded-xl border font-black text-sm transition-all ${
                    profile.topLevelCategory === level 
                    ? 'bg-[#f58434] border-[#f58434] text-white shadow-md' 
                    : 'bg-white border-slate-200 text-[#2c4869] hover:border-[#f58434]/30'
                  } ${!isEditing && profile.topLevelCategory !== level ? 'hidden' : ''}`}
                >
                  {level}
                </button>
              ))}
            </div>
          </div>

          {profile.topLevelCategory && (
            <div className="space-y-3">
              <label className="block text-sm font-black text-[#2c4869] mb-2 uppercase tracking-tight">Subject area you're most interested in</label>
              <select 
                disabled={!isEditing}
                value={profile.specializationCategory}
                onChange={(e) => updateProfile({ specializationCategory: e.target.value, specialization: '' })}
                className="w-full px-4 py-3 rounded-xl border border-slate-200 outline-none transition-all text-sm font-medium focus:ring-2 focus:ring-[#f58434]"
              >
                <option value="">Select Area</option>
                {categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
              </select>
            </div>
          )}

          {profile.specializationCategory && (
            <div className="space-y-3">
              <label className="block text-sm font-black text-[#2c4869] mb-2 uppercase tracking-tight">Specialization you would like to pursue or you are currently pursuing</label>
              <select 
                disabled={!isEditing}
                value={profile.specialization}
                onChange={(e) => updateProfile({ specialization: e.target.value })}
                className="w-full px-4 py-3 rounded-xl border border-slate-200 outline-none transition-all text-sm font-medium focus:ring-2 focus:ring-[#f58434]"
              >
                <option value="">Select Specialization</option>
                {subFields.map(sub => <option key={sub} value={sub}>{sub}</option>)}
              </select>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

