  if (!showWhatsAppInput && !showConfirmation) {
    return (
      <div className="min-h-screen bg-[#2c4869] flex flex-col items-center relative overflow-hidden">
        <div className="w-full py-3 text-center border-b border-white/5 bg-[#2c4869]/80 z-20 sticky top-0 backdrop-blur-md">
          <div className="flex flex-col items-center gap-0.5">
            <span className="text-[10px] font-black text-[#ffcd29] uppercase tracking-[0.3em] leading-none">Quick Self-Reflection Tool</span>
            <span className="text-[9px] font-semibold text-white/70 uppercase tracking-[0.15em] leading-none">by VigyanShaala International</span>
          </div>
        </div>
        <div className="absolute top-[-10%] right-[-10%] w-96 h-96 bg-[#f58434]/20 rounded-full blur-[100px]" />
        <div className="absolute bottom-[-10%] left-[-10%] w-96 h-96 bg-[#ffcd29]/10 rounded-full blur-[100px]" />

        <div className="flex-1 flex flex-col justify-center items-center relative z-10 text-center max-w-2xl w-full px-6 py-12">
          <div className="mb-12 bg-white/10 p-4 rounded-3xl backdrop-blur-md border border-white/5 shadow-2xl">
            <img src={VIGYAN_SHAALA_LOGO} alt="VigyanShaala Logo" className="h-16 sm:h-20 object-contain brightness-0 invert" />
          </div>
          <div className="animate-in fade-in zoom-in-95 duration-500 w-full flex flex-col items-center">
            <h1 className="text-4xl sm:text-5xl font-black text-white mb-6 leading-tight">Reflect on your <span className="text-[#ffcd29]">STEM</span> Journey.</h1>
            <div className="bg-white/5 backdrop-blur-sm border border-white/10 p-6 rounded-3xl mb-10 text-left">
              <p className="text-white/80 text-sm sm:text-base leading-relaxed text-center font-medium">
                Organize your academic insights for personalized career guidance with 
                <span className="text-[#f58434] font-black italic ml-1">Curie</span> - your AI mentor from VigyanShaala designed to guide you through your STEM journey.
