            <div className="flex flex-col gap-4 w-full max-w-sm mx-auto">
              <button onClick={() => onStart()} className="w-full bg-[#f58434] hover:bg-[#f58434]/90 text-white font-black py-5 px-8 rounded-2xl transition-all shadow-xl shadow-[#f58434]/20 text-lg active:scale-95">Start Reflecting</button>
              <button onClick={() => setShowWhatsAppInput(true)} className="w-full bg-white/5 hover:bg-white/10 text-white/80 font-bold py-4 px-8 rounded-2xl transition-all border border-white/10 text-base active:scale-95 flex items-center justify-center gap-2">
