                Retrieve from Curie to Update
              </button>
              {hasDraft && (
                <button onClick={handleFetchDraft} disabled={isFetching} className="w-full bg-[#2c4869]/40 hover:bg-[#2c4869]/60 text-white/60 font-black py-3 px-8 rounded-2xl transition-all border border-white/5 text-xs active:scale-95 flex items-center justify-center gap-2">
