    const trimmed = value.trim();
    const currentList = (profile[field] as string[]) || [];
    if (trimmed && !currentList.includes(trimmed)) {
      updateProfile({ [field]: [...currentList, trimmed] });
      if (setter) setter('');
    }
  };

  const removeFromList = (field: keyof Profile, value: string) => {
    if (!isEditing) return;
    const currentList = (profile[field] as string[]) || [];
    updateProfile({ [field]: currentList.filter(x => x !== value) });
  };

  const toggleExam = (exam: string) => {
    if (!isEditing) return;
    const currentExams = profile.competitiveExams || [];
    const next = currentExams.includes(exam)
      ? currentExams.filter(e => e !== exam)
      : [...currentExams, exam];
    updateProfile({ competitiveExams: next });
  };

  const handleSave = () => {
    if (isEditing) {
      setShowBurst(true);
      setTimeout(() => setShowBurst(false), 2000);
    }
    setIsEditing(!isEditing);
  };

  const InputRow = ({ value, onChange, onAdd, placeholder }: any) => (
    <div className={`flex gap-2 mb-4 ${!isEditing ? 'hidden' : ''}`}>
      <input 
        type="text" 
        value={value}
        onChange={(e) => onChange(e.target.value)}
        onKeyPress={(e) => e.key === 'Enter' && onAdd()}
        placeholder={placeholder}
        className="flex-1 px-4 py-3 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-[#f58434] transition-all text-sm font-medium"
      />
      <button onClick={onAdd} className="px-5 py-3 bg-[#f58434] text-white rounded-xl text-xs font-black uppercase tracking-widest hover:bg-[#f58434]/90 transition-all shadow-md">Add</button>
    </div>
  );

  const TagCloud = ({ items, field, color = "vs-orange" }: { items: string[], field: keyof Profile, color?: string }) => {
    const safeItems = items || [];
    const colorStyles: Record<string, string> = {
      'vs-orange': 'bg-[#f58434]/10 text-[#f58434] border-[#f58434]/20',
      'vs-yellow': 'bg-[#ffcd29]/10 text-[#b58e00] border-[#ffcd29]/20',
      'vs-blue': 'bg-[#2c4869]/10 text-[#2c4869] border-[#2c4869]/20'
    };

    return (
      <div className={`flex flex-wrap gap-2 min-h-[40px]`}>
        {safeItems.length > 0 ? safeItems.map(item => (
          <span key={item} className={`px-3 py-2 rounded-xl text-xs flex items-center gap-2 border font-black shadow-sm animate-in zoom-in-90 duration-300 ${colorStyles[color] || colorStyles['vs-orange']}`}>
            {item}
            {isEditing && (
              <button onClick={() => removeFromList(field, item)} className="hover:text-red-500 text-lg leading-none">&times;</button>
            )}
          </span>
        )) : <span className="text-xs text-slate-300 italic font-medium py-2">No entries yet...</span>}
      </div>
    );
  };

  const TabButton = ({ id, label, subtitle, color }: { id: ExpertiseTab, label: string, subtitle: string, color: string }) => (
    <button
      onClick={() => setActiveTab(id)}
      className={`flex-1 min-w-[140px] p-4 rounded-2xl border transition-all flex flex-col items-center gap-1 text-center ${
        activeTab === id 
        ? `${color} border-current shadow-lg scale-[1.02]` 
        : 'bg-white border-slate-200 text-slate-400 hover:border-slate-300'
      }`}
    >
      <span className="text-[10px] font-black uppercase tracking-widest leading-tight">{label}</span>
      <span className="text-[8px] font-bold opacity-60 italic">{subtitle}</span>
    </button>
  );

  return (
    <div className="space-y-8 animate-in slide-in-from-right-4 duration-500 pb-20">
      <EmojiBurst trigger={showBurst} emojis={['🛠️', '💻', '🚀', '⚙️', '🏗️']} />

      <div className="flex justify-end items-center mb-2">
        <button 
          onClick={handleSave}
          className={`flex items-center gap-2 px-4 py-1.5 rounded-lg text-xs font-black transition-all border ${
            isEditing ? 'bg-[#2c4869] text-white border-[#2c4869] shadow-lg' : 'bg-white text-[#f58434] border-[#f58434]/20 hover:bg-[#f58434]/5 shadow-sm'
          }`}
        >
          {isEditing ? (
            <><svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg> Save Core</>
          ) : (
            <><svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg> Edit Core</>
          )}
        </button>
      </div>

      <div className="flex gap-2 overflow-x-auto no-scrollbar pb-2">
        <TabButton id="technical" label="Technical Stack" subtitle="Hard Skills" color="bg-[#f58434]/5 text-[#f58434]" />
        <TabButton id="professional" label="Professional Skills" subtitle="Soft Skills" color="bg-[#ffcd29]/5 text-[#b58e00]" />
        <TabButton id="projects" label="Key Projects" subtitle="Evidence" color="bg-[#2c4869]/5 text-[#2c4869]" />
        <TabButton id="exams" label="Exams & Certs" subtitle="Achievements" color="bg-[#2c4869]/5 text-[#2c4869]" />
      </div>

      <div className={`p-6 bg-white rounded-3xl border border-slate-100 shadow-sm transition-all duration-300 ${!isEditing ? 'opacity-80' : 'opacity-100'}`}>
        {activeTab === 'technical' && (
          <section className="animate-in fade-in slide-in-from-bottom-2 duration-300">
            <h3 className="text-xs font-black text-[#f58434] uppercase tracking-[0.2em] mb-4">Hard Technical Skills</h3>
            <InputRow value={skillInput} onChange={setSkillInput} onAdd={() => addToList('technicalSkills', skillInput, setSkillInput)} placeholder="e.g. Python, AWS, SolidWorks..." />
            <TagCloud items={profile.technicalSkills} field="technicalSkills" color="vs-orange" />
          </section>
        )}

        {activeTab === 'professional' && (
          <section className="animate-in fade-in slide-in-from-bottom-2 duration-300">
            <h3 className="text-xs font-black text-[#b58e00] uppercase tracking-[0.2em] mb-4">Professional & Soft Skills</h3>
            <InputRow value={softSkillInput} onChange={setSoftSkillInput} onAdd={() => addToList('softSkills', softSkillInput, setSoftSkillInput)} placeholder="e.g. Scientific Communication, Team Management..." />
            <TagCloud items={profile.softSkills} field="softSkills" color="vs-yellow" />
          </section>
        )}

        {activeTab === 'projects' && (
          <section className="animate-in fade-in slide-in-from-bottom-2 duration-300">
            <h3 className="text-xs font-black text-[#2c4869] uppercase tracking-[0.2em] mb-4">Key Academic & Personal Projects</h3>
            <InputRow value={projectInput} onChange={setProjectInput} onAdd={() => addToList('projects', projectInput, setProjectInput)} placeholder="e.g. Low-cost Ventilator, Rainfall Predictor..." />
            <TagCloud items={profile.projects} field="projects" color="vs-blue" />
          </section>
        )}

        {activeTab === 'exams' && (
          <section className="animate-in fade-in slide-in-from-bottom-2 duration-300">
            <h3 className="text-xs font-black text-[#2c4869] uppercase tracking-[0.2em] mb-6">Competitive Exams & Certifications</h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mb-6">
              {COMPETITIVE_EXAMS.map(exam => {
                const selected = profile.competitiveExams.includes(exam);
                if (!isEditing && !selected) return null;
                return (
                  <button
                    key={exam}
                    disabled={!isEditing}
                    onClick={() => toggleExam(exam)}
                    className={`text-left px-4 py-3 rounded-xl border transition-all text-[11px] font-black flex items-center justify-between ${
                      selected 
                      ? 'bg-[#2c4869] text-white border-[#2c4869] shadow-sm' 
                      : 'bg-slate-50 text-[#2c4869]/60 border-slate-200 hover:border-[#f58434]/30'
                    }`}
                  >
                    {exam}
                    {selected && <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg>}
                  </button>
                );
              })}
            </div>

            {profile.competitiveExams.includes('Other') && (
              <div className="animate-in slide-in-from-top-2 duration-300 bg-slate-50 p-5 rounded-2xl border border-dashed border-slate-200">
                <label className="block text-[10px] font-black text-[#2c4869] uppercase tracking-widest mb-3">Specify your other Exams or Certifications</label>
                <textarea 
                  readOnly={!isEditing}
                  value={profile.customExam}
                  onChange={(e) => updateProfile({ customExam: e.target.value })}
                  placeholder="List them here, separated by commas..."
                  className="w-full min-h-[100px] p-4 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-[#f58434] transition-all text-sm font-medium bg-white"
                />
              </div>
            )}
          </section>
        )}
      </div>
    </div>
  );
};

export default ExpertiseForm;

import React, { useState, useMemo } from 'react';
import { Profile, Section } from '../types';
import { REFLECTION_PROMPTS } from '../constants';

interface Props {
  profile: Profile;
  setCurrentSection: (s: Section) => void;
}

const VIGYAN_SHAALA_LOGO = "https://vigyanshaala.com/wp-content/uploads/2021/01/VigyanShaala-Logo-Horizontal-1.png";
const STORAGE_KEY = 'vs_reflection_profile';

const ReviewPage: React.FC<Props> = ({ profile, setCurrentSection }) => {
  const [isSaved, setIsSaved] = useState(false);
  const [isUpdatingCurie, setIsUpdatingCurie] = useState(false);
  const [curieSuccess, setCurieSuccess] = useState(false);
  const [showIncompleteWarning, setShowIncompleteWarning] = useState(false);

  const incompleteFields = useMemo(() => {
    const missing: { section: Section, label: string }[] = [];

    // Identity
    if (!profile.fullName) missing.push({ section: Section.BASIC, label: 'Full Name' });
    if (!profile.email) missing.push({ section: Section.BASIC, label: 'Email Address' });
    if (!profile.location) missing.push({ section: Section.BASIC, label: 'Current Location' });

    // Academic
    if (!profile.collegeName) missing.push({ section: Section.ACADEMIC, label: 'College/University' });
    if (!profile.degreeType) missing.push({ section: Section.ACADEMIC, label: 'Degree Type' });
    if (!profile.topLevelCategory) missing.push({ section: Section.ACADEMIC, label: 'STEM Stream' });

    // Expertise
    if (profile.technicalSkills.length === 0) missing.push({ section: Section.SKILLS, label: 'Technical Stack' });
    if (profile.softSkills.length === 0) missing.push({ section: Section.SKILLS, label: 'Professional Skills' });
    if (profile.projects.length === 0) missing.push({ section: Section.SKILLS, label: 'Key Projects' });

    // Reflections
    REFLECTION_PROMPTS.forEach(prompt => {
      if (!profile.reflections[prompt.key] || profile.reflections[prompt.key].trim().length < 5) {
        missing.push({ section: Section.REFLECTIONS, label: prompt.label });
      }
    });

    return missing;
  }, [profile]);

  const saveLocally = () => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(profile));
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 3000);
  };

  const handleUpdateCurie = () => {
    // If there are missing fields and we haven't shown the warning yet, show it.
    if (incompleteFields.length > 0 && !showIncompleteWarning) {
      setShowIncompleteWarning(true);
      // Scroll to the warning
      document.getElementById('incomplete-warning')?.scrollIntoView({ behavior: 'smooth', block: 'center' });
      return;
    }

    localStorage.setItem(STORAGE_KEY, JSON.stringify(profile));
    setIsUpdatingCurie(true);

    setTimeout(() => {
      setIsUpdatingCurie(false);
      setCurieSuccess(true);
      setShowIncompleteWarning(false);
      setTimeout(() => setCurieSuccess(false), 10000);
    }, 2000);
  };

  const downloadPdf = () => {
    window.print();
  };

  const InfoBlock = ({ label, value, section }: { label: string, value: string | string[], section: Section }) => (
    <div className="mb-4 group">
      <div className="flex justify-between items-start mb-1">
        <span className="text-[10px] font-black text-[#2c4869]/40 uppercase tracking-widest">{label}</span>
        <button 
          onClick={() => setCurrentSection(section)}
          className="text-[10px] font-black text-[#f58434] opacity-0 group-hover:opacity-100 transition-opacity uppercase no-print"
        >
          Edit
        </button>
      </div>
      <div className="text-[#2c4869] text-sm font-black break-words leading-relaxed">
        {Array.isArray(value) 
          ? (value.length > 0 ? value.join(', ') : <span className="text-slate-300 italic text-xs font-medium">Not specified</span>) 
          : (value || <span className="text-slate-300 italic text-xs font-medium">Not specified</span>)}
      </div>
    </div>
  );

  const displayCategory = profile.specializationCategory === 'Other' 
    ? profile.customCategory || 'Other' 
    : profile.specializationCategory;

  const displaySpecialization = profile.specialization === 'Other' 
    ? profile.customSpecialization || 'Other' 
    : profile.specialization;

  const specDisplay = [
    profile.topLevelCategory,
    displayCategory,
    displaySpecialization
  ].filter(Boolean).join(' / ');

  return (
    <div className="space-y-8 animate-in zoom-in-95 duration-500 pb-20">
      <div className="bg-white p-6 sm:p-10 rounded-3xl border border-slate-200 shadow-2xl overflow-hidden relative print:shadow-none print:border-none print:p-0">
        <div className="absolute top-0 right-0 p-6 sm:p-10 flex flex-col items-end gap-3 print:static print:flex-row print:justify-between print:w-full print:p-0 print:mb-8">
           <img 
            src={VIGYAN_SHAALA_LOGO} 
            alt="VigyanShaala" 
            className="h-10 object-contain opacity-80"
           />
           <div className="w-14 h-14 bg-[#2c4869] rounded-2xl transform rotate-12 flex items-center justify-center text-white font-black text-3xl shadow-xl print:rotate-0 print:shadow-none">
             {profile.fullName ? profile.fullName.charAt(0).toUpperCase() : '?'}
           </div>
        </div>

        <div className="mb-10 print:mt-4">
          <h2 className="text-2xl font-black text-[#2c4869] leading-tight">Structured Profile Data</h2>
          <p className="text-[#2c4869]/50 text-xs mt-1 uppercase tracking-wider font-black">Generated via VigyanShaala Reflection Tool</p>
        </div>

        <section className="mb-10">
          <h3 className="text-xs font-black text-[#f58434] mb-6 border-b border-[#f58434]/10 pb-2 uppercase tracking-widest">Foundation</h3>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-8 gap-y-2">
            <InfoBlock label="Full Name" value={profile.fullName} section={Section.BASIC} />
            <InfoBlock label="Location" value={profile.location} section={Section.BASIC} />
            <InfoBlock label="Institution" value={profile.collegeName} section={Section.ACADEMIC} />
            <InfoBlock label="Degree Path" value={`${profile.degreeType} in ${specDisplay}`} section={Section.ACADEMIC} />
            <InfoBlock label="Current CGPA" value={profile.cgpa} section={Section.ACADEMIC} />
            <InfoBlock label="Academic Interests" value={profile.interests} section={Section.SKILLS} />
          </div>
        </section>

        <section className="mb-10">
          <h3 className="text-xs font-black text-[#ffcd29] mb-6 border-b border-[#ffcd29]/10 pb-2 uppercase tracking-widest">Capabilities & Skills</h3>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-8">
            <InfoBlock label="Technical Skills" value={profile.technicalSkills} section={Section.SKILLS} />
            <InfoBlock label="Soft Skills" value={profile.softSkills} section={Section.SKILLS} />
          </div>
        </section>

        <section className="mb-10">
          <h3 className="text-xs font-black text-[#2c4869] mb-6 border-b border-[#2c4869]/10 pb-2 uppercase tracking-widest">Experiences</h3>
          <div className="space-y-2">
            <InfoBlock label="Internships/Work" value={profile.internships} section={Section.SKILLS} />
            <InfoBlock label="Projects" value={profile.projects} section={Section.SKILLS} />
            <InfoBlock label="Volunteering" value={profile.volunteering} section={Section.SKILLS} />
            <InfoBlock label="Exams & Certs" value={profile.competitiveExams} section={Section.SKILLS} />
          </div>
        </section>

        <section className="mb-10">
          <h3 className="text-xs font-black text-[#f58434] mb-6 border-b border-[#f58434]/10 pb-2 uppercase tracking-widest">Reflection & SWOT</h3>
          <div className="space-y-6">
            <InfoBlock label="Personal Superpower" value={profile.reflections.strengths} section={Section.REFLECTIONS} />
            <InfoBlock label="Toughest Concept" value={profile.reflections.toughestConcept} section={Section.REFLECTIONS} />
            <InfoBlock label="Primary Curiosity" value={profile.reflections.technicalObsession} section={Section.REFLECTIONS} />
            <InfoBlock label="Proudest Spark" value={profile.reflections.proudestAchievement} section={Section.REFLECTIONS} />
            <InfoBlock label="Societal Impact" value={profile.reflections.societalImpact} section={Section.REFLECTIONS} />
          </div>
        </section>

        <div className="space-y-6 no-print">
          {showIncompleteWarning && incompleteFields.length > 0 && (
            <div id="incomplete-warning" className="bg-[#f58434]/5 border-2 border-[#f58434] rounded-3xl p-6 animate-in slide-in-from-top-4 duration-500">
              <div className="flex items-start gap-4">
                <div className="bg-[#f58434] text-white p-2 rounded-xl">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 17c-.77 1.333.192 3 1.732 3z" />
                  </svg>
                </div>
                <div className="flex-1">
                  <h4 className="text-lg font-black text-[#2c4869] uppercase leading-tight">Wait! Some sections are still empty.</h4>
                  <p className="text-sm font-medium text-[#2c4869]/70 mt-1 mb-4">Sharing a complete profile helps us give you the most accurate career guidance.</p>

                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 mb-6">
                    {incompleteFields.slice(0, 6).map((field, idx) => (
                      <button 
                        key={idx}
                        onClick={() => setCurrentSection(field.section)}
                        className="flex items-center gap-2 text-left bg-white/50 border border-slate-200 px-3 py-2 rounded-xl text-[11px] font-black text-[#f58434] hover:bg-white transition-all"
                      >
                        <span className="w-1.5 h-1.5 bg-[#f58434] rounded-full"></span>
                        {field.label}
                      </button>
                    ))}
                    {incompleteFields.length > 6 && (
                      <div className="text-[10px] font-black text-[#2c4869]/40 p-2 italic">
                        + {incompleteFields.length - 6} more empty spaces...
                      </div>
                    )}
                  </div>

                  <div className="flex flex-col sm:flex-row gap-3">
                    <button 
                      onClick={() => setCurrentSection(incompleteFields[0].section)}
                      className="flex-1 bg-[#2c4869] text-white py-3 rounded-2xl font-black text-xs uppercase tracking-widest hover:opacity-90 transition-all shadow-md"
                    >
                      Fill them now
                    </button>
                    <button 
                      onClick={() => { setShowIncompleteWarning(false); handleUpdateCurie(); }}
                      className="flex-1 bg-transparent text-[#2c4869]/40 hover:text-[#2c4869] py-3 rounded-2xl font-black text-xs uppercase tracking-widest transition-all"
                    >
                      Sync Anyway
                    </button>
                  </div>
                </div>
              </div>
            </div>
          )}

          <div className="space-y-3">
            <button 
              onClick={handleUpdateCurie}
              disabled={isUpdatingCurie}
              className={`w-full py-7 rounded-3xl font-black flex flex-col items-center justify-center gap-1 transition-all shadow-2xl active:scale-[0.98] border-2 ${
                curieSuccess
                ? 'bg-emerald-50 border-emerald-500 text-emerald-700'
                : 'bg-[#f58434] text-white hover:opacity-95 border-transparent'
              }`}
            >
              {isUpdatingCurie ? (
                <div className="flex items-center gap-3">
                  <div className="w-6 h-6 border-3 border-white/30 border-t-white rounded-full animate-spin" />
                  <span className="text-xl uppercase tracking-tight">Syncing & Saving...</span>
                </div>
              ) : curieSuccess ? (
                <div className="animate-in fade-in duration-500 text-center px-4">
                  <div className="flex items-center justify-center gap-2 mb-1">
                    <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" />
                    </svg>
                    <span className="text-xl uppercase tracking-tight">Synced & Saved!</span>
                  </div>
                  <p className="text-[11px] font-black text-emerald-600 leading-tight">
                    You can return here any time to review and update your profile
                  </p>
                </div>
              ) : (
                <>
                  <span className="text-xl uppercase tracking-tight">Update my profile on Curie</span>
                  <span className="text-xs font-black opacity-80 uppercase tracking-widest">Sync reflections for better guidance</span>
                </>
              )}
            </button>
            <div className="text-center flex flex-col items-center">
              <p className="text-[10px] text-[#2c4869]/40 font-bold italic mb-1">
                Your data is shared only with Curie for personalized support.
              </p>
              <button 
                onClick={() => window.open('https://vigyanshaala.com/privacy-policy/', '_blank')}
                className="text-[10px] text-[#f58434] hover:text-[#f58434]/80 underline underline-offset-2 transition-colors font-bold"
              >
                Click to know more about our Data Privacy Policy
              </button>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="relative group">
              <button 
                onClick={saveLocally}
                className={`w-full py-4 rounded-2xl font-black flex items-center justify-center gap-2 transition-all shadow-md active:scale-[0.98] border ${
                  isSaved 
                  ? 'bg-emerald-100 text-emerald-700 border-emerald-500' 
                  : 'bg-white text-[#2c4869] border-[#2c4869]/10 hover:bg-slate-50'
                }`}
              >
                {isSaved ? (
                  <>
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" />
                    </svg>
                    Saved Locally
                  </>
                ) : "Quick Save"}
              </button>
              <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-3 w-48 p-2 bg-[#2c4869] text-white text-[10px] leading-tight rounded-lg shadow-xl opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none text-center z-40 hidden sm:block font-bold">
                This will save your data on the app, but will not sync data on Curie
                <div className="absolute top-full left-1/2 -translate-x-1/2 border-8 border-transparent border-t-[#2c4869]"></div>
              </div>
            </div>

            <button 
              onClick={downloadPdf}
              className="py-4 rounded-2xl bg-[#2c4869] text-white font-black flex items-center justify-center gap-2 hover:bg-[#2c4869]/90 transition-all shadow-md active:scale-[0.98]"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
              </svg>
              Download PDF
            </button>
          </div>
        </div>
      </div>
    </div>
  );
